// Quiz content for Cours30 — Harmonie impressionniste et modalité avancée

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours30Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // ── Topic 1 : Le planing (parallélisme) — 12 questions ───────────────────

  { q: "Qu'est-ce que le planing en harmonie impressionniste ?", opts: ["Une technique de résolution de dissonance", "Un déplacement d'un accord entier en parallèle sans résolution fonctionnelle", "Une gamme par tons entiers", "Un enchaînement V–I caractéristique"], a: 1, fb: "Le planing est le glissement d'un accord complet (avec toutes ses voix) en mouvement parallèle. La couleur de l'accord se déplace sans que les tensions se résolvent — l'effet est de 'bloc sonore qui glisse'." },

  { q: "Quelle est la différence entre le planing diatonique et le planing chromatique ?", opts: ["Le planing diatonique utilise des demi-tons, le chromatique des tons entiers", "Le planing diatonique conserve le même type d'accord sur chaque degré de la gamme, le chromatique transpose le même accord exact", "Le planing diatonique est propre à Ravel, le chromatique à Debussy", "Il n'y a aucune différence — les deux termes désignent la même technique"], a: 1, fb: "Planing diatonique : les accords changent de qualité selon les degrés de la gamme (ex. accords de sixte en tierce parallèle). Planing chromatique : le même accord exact (même qualité) glisse chromatiquement — toutes les voix bougent du même intervalle." },

  { q: "Dans le planing chromatique, qu'advient-il aux accords quand ils se déplacent ?", opts: ["Ils changent de qualité (majeur → mineur selon le degré)", "Ils gardent exactement la même structure d'intervalles — seule la hauteur change", "Ils perdent leurs quintes pour éviter les parallèles", "Ils se résolvent vers la tonique à chaque déplacement"], a: 1, fb: "Dans le planing chromatique, l'accord se transpose exactement : si c'est un accord de 7e de dominante, il reste un accord de 7e de dominante à chaque étape. La qualité est préservée, seule la hauteur varie." },

  { q: "Pourquoi les quintes et octaves parallèles sont-elles tolérées dans le planing ?", opts: ["Parce qu'elles sont rares dans le planing", "Parce que le planing fonctionne précisément sur cet effet de bloc sonore parallèle — c'est voulu, pas une faute", "Parce que Debussy ignorait les règles du contrepoint", "Parce qu'elles sont compensées par des dissonances résolues"], a: 1, fb: "Le planing contredit délibérément les règles du contrepoint classique. Les quintes parallèles créent l'effet de 'bloc' caractéristique — le son glisse comme un seul objet. C'est une esthétique, pas une négligence." },

  { q: "Quel compositeur est le maître incontesté du planing impressionniste ?", opts: ["César Franck", "Claude Debussy", "Johannes Brahms", "Ludwig van Beethoven"], a: 1, fb: "Claude Debussy est le créateur et maître du planing impressionniste. Sa pièce 'La Cathédrale engloutie' et ses préludes débordent d'accords en mouvement parallèle qui créent des effets de couleur sonore sans résolution fonctionnelle." },

  { q: "Comment analyser le planing — avec les fonctions T/SD/D ou autrement ?", opts: ["Avec les fonctions T/SD/D classiques, comme tout accord tonal", "Par couleur et registre : identifier l'accord de départ, noter le mouvement, décrire l'effet sonore", "Par analyse schenkérienne uniquement", "On ne peut pas analyser le planing — c'est de l'improvisation"], a: 1, fb: "L'analyse fonctionnelle (T/SD/D) ne s'applique pas au planing : il n'y a pas de tension-résolution au sens classique. On analyse par couleur (type d'accord), registre (grave/aigu) et effet (flottement, opacité, clarté)." },

  { q: "Dans le planing diatonique, si on commence sur I (accord majeur), l'accord sur II sera :", opts: ["Toujours majeur", "Mineur, car II est mineur dans la gamme majeure", "Diminué, car II est diminué", "Augmenté, car la gamme le demande"], a: 1, fb: "En planing diatonique, les accords suivent la qualité diatonique de chaque degré. En Do majeur, II est Ré mineur (Ré–Fa–La). Le planing diatonique préserve l'armure — les accords changent de qualité selon le degré." },

  { q: "La pièce 'La Cathédrale engloutie' de Debussy utilise massivement :", opts: ["Des dominantes secondaires classiques", "Des accords de quartes empilées", "Des accords en planing parallèle pour évoquer les cloches sous l'eau", "Des gammes dodécaphoniques"], a: 2, fb: "'La Cathédrale engloutie' emploie des blocs d'accords (souvent quintes et quartes) en mouvement parallèle pour simuler les résonances de cloches. Le planing crée l'effet d'immersion aquatique caractéristique de la pièce." },

  { q: "Le planing est apparu principalement dans quel courant musical ?", opts: ["Le contrepoint baroque", "L'harmonie romantique allemande (Brahms, Wagner)", "L'impressionnisme français (Debussy, Ravel)", "Le dodécaphonisme viennois (Schoenberg)"], a: 2, fb: "Le planing est une technique caractéristique de l'impressionnisme français, développée par Debussy et Ravel à la fin du XIXe et début du XXe siècle. Il s'inspire de la musique japonaise (gamelan) et des estampes orientales." },

  { q: "Dans le planing, qu'est-ce qui remplace la fonction harmonique classique ?", opts: ["Le contrepoint strict à 4 voix", "La couleur sonore, le registre et le timbre de l'accord", "La progression par tritons", "L'alternance strict mineur/majeur"], a: 1, fb: "En harmonie impressionniste, la couleur (qualité de l'accord : majeur, 7e, 9e), le registre (grave, médium, aigu) et le timbre (position ouverte ou fermée) remplacent la logique tension-résolution du système tonal." },

  { q: "Un accord Maj7 en planing chromatique qui monte d'un demi-ton devient :", opts: ["Un accord mineur", "Le même type d'accord Maj7 mais un demi-ton plus haut", "Un accord diminué", "Un accord de dominante 7e"], a: 1, fb: "En planing chromatique, la structure de l'accord est preservée. Do Maj7 (Do–Mi–Sol–Si) transporté un demi-ton plus haut donne Réb Maj7 (Réb–Fa–Lab–Do). Même structure d'intervalles, hauteur différente." },

  { q: "Quelle est la sensation auditive typique du planing ?", opts: ["Tension croissante vers une résolution forte", "Un glissement coloré sans direction fonctionnelle — comme une aquarelle sonore", "Un renforcement de la tonalité principale", "Une dissolution vers le silence"], a: 1, fb: "Le planing crée une sensation de glissement ou de flottement — l'accord se meut comme un objet unique dans l'espace sonore. Il n'y a pas de direction fonctionnelle vers une résolution, juste un déplacement de couleur." },

  // ── Topic 2 : La gamme par tons — 12 questions ────────────────────────────

  { q: "Combien de notes contient la gamme par tons ?", opts: ["5 notes", "6 notes", "7 notes", "8 notes"], a: 1, fb: "La gamme par tons contient 6 notes, toutes séparées d'un ton entier (2 demi-tons). Exemple : Do–Ré–Mi–Fa#–Sol#–La# (puis retour à Do). Il n'existe que 2 gammes par tons distinctes (toutes les autres sont des transpositions identiques à l'une ou l'autre)." },

  { q: "Quel est l'intervalle entre chaque note de la gamme par tons ?", opts: ["Un demi-ton (½T)", "Un ton entier (T)", "Une tierce mineure (T½)", "Un triton"], a: 1, fb: "Chaque degré de la gamme par tons est séparé du suivant par un ton entier (2 demi-tons). C'est ce qui donne à cette gamme sa symétrie totale et l'absence de note directrice." },

  { q: "Pourquoi la gamme par tons ne contient-elle pas de note directrice (sensible) ?", opts: ["Par erreur de construction", "Parce que tous les intervalles sont identiques (tons entiers) — aucun demi-ton ne crée de tension directionnelle", "Parce qu'elle est pentatonique", "Parce qu'elle commence sur Do"], a: 1, fb: "La sensible fonctionne grâce au demi-ton qui crée une tension vers la tonique. Dans la gamme par tons, tous les intervalles sont des tons entiers — aucun demi-ton, donc aucune tension directionnelle, donc aucune note directrice. Le flottement est total." },

  { q: "Quel type d'accord produit naturellement la gamme par tons ?", opts: ["L'accord parfait majeur (tierce M + quinte J)", "L'accord augmenté (tierce M + tierce M)", "L'accord diminué (tierce m + tierce m)", "L'accord de dominante 7e"], a: 1, fb: "La gamme par tons produit des accords augmentés : en empilant des tierces sur les degrés de la gamme par tons, on obtient systématiquement des tierces majeures superposées. Ex. : Do–Mi–Sol# = accord augmenté." },

  { q: "Combien de transpositions distinctes possède la gamme par tons ?", opts: ["6 transpositions distinctes", "7 transpositions distinctes", "2 transpositions distinctes seulement", "12 transpositions distinctes"], a: 2, fb: "La gamme par tons ne peut être transposée que de 2 façons distinctes avant de revenir à elle-même. Ex. : Do–Ré–Mi–Fa#–Sol#–La# et Réb–Mib–Fa–Sol–La–Si. Toutes les autres 'transpositions' redonnent l'une de ces deux gammes." },

  { q: "Quel célèbre prélude de Debussy est entièrement construit sur la gamme par tons ?", opts: ["Clair de Lune", "La Fille aux cheveux de lin", "Voiles", "La Cathédrale engloutie"], a: 2, fb: "'Voiles' (Préludes Livre I, 1909) est l'exemple le plus connu de pièce entièrement construite sur la gamme par tons. La partie centrale emploie la pentatonique, créant un contraste de couleur saisissant." },

  { q: "La gamme par tons Do–Ré–Mi–Fa#–Sol#–La# produit quel accord sur Do ?", opts: ["Do majeur (Do–Mi–Sol)", "Do augmenté (Do–Mi–Sol#)", "Do mineur (Do–Mib–Sol)", "Do diminué (Do–Mib–Solb)"], a: 1, fb: "En construisant un accord sur Do dans la gamme par tons (Do–Ré–Mi–Fa#–Sol#–La#), on prend Do, Mi (tierce M), Sol# (tierce M supplémentaire) = Do augmenté. Tous les accords de cette gamme sont augmentés." },

  { q: "Quelle est la couleur sonore caractéristique de la gamme par tons ?", opts: ["Tension forte, destabilisante, résolution urgente", "Flottement, dissolution tonale, mystère onirique", "Clarté diatonique, structure solide", "Violence rythmique, couleur slave"], a: 1, fb: "La gamme par tons crée un flottement tonal total — sans note directrice, sans demi-ton, l'oreille ne peut s'orienter vers aucune tonique. L'effet est onirique, mystérieux, dissous — exactement l'esthétique impressionniste de Debussy." },

  { q: "La gamme par tons est aussi appelée le mode __ de Messiaen.", opts: ["Mode 2", "Mode 3", "Mode 1", "Mode 4"], a: 2, fb: "Messiaen a systématisé les gammes symétriques dans son traité 'Technique de mon langage musical' (1944). La gamme par tons est son mode 1 — le plus simple, avec seulement 2 transpositions possibles." },

  { q: "Entre la gamme par tons sur Do et la gamme par tons sur Réb, combien de notes sont communes ?", opts: ["Aucune note commune", "3 notes communes", "Toutes les notes — ce sont les mêmes", "1 seule note commune"], a: 0, fb: "Les deux gammes par tons distinctes (Do–Ré–Mi–Fa#–Sol#–La# et Réb–Mib–Fa–Sol–La–Si) n'ont aucune note en commun (les enharmonies mises à part). Elles partagent les 12 demi-tons ensemble." },

  { q: "Pourquoi peut-on dire que la gamme par tons est 'parfaitement symétrique' ?", opts: ["Parce qu'elle a 7 degrés comme la gamme majeure", "Parce que tous ses intervalles sont identiques — elle peut être lue de n'importe quel degré et donner la même gamme", "Parce qu'elle contient un triton en son centre", "Parce qu'elle alterne tons et demi-tons"], a: 1, fb: "La symétrie parfaite de la gamme par tons vient de l'uniformité de ses intervalles. Quelle que soit la note de départ dans la gamme, la succession d'intervalles est identique (T–T–T–T–T–T). C'est une propriété que ne possède pas la gamme majeure." },

  { q: "Dans quel contexte pédagogique distingue-t-on la gamme par tons de la gamme pentatonique ?", opts: ["Elles sont interchangeables — même effet sonore", "La gamme par tons a 6 notes, flottement total, accords augmentés ; la pentatonique a 5 notes, sérénité, pas d'accord de dominante", "La gamme par tons est majeure, la pentatonique est mineure", "La gamme par tons vient d'Asie, la pentatonique vient de France"], a: 1, fb: "Distinction essentielle : gamme par tons = 6 notes, tons entiers seulement, flottement tonal, accords augmentés. Pentatonique = 5 notes, sans demi-ton mais pas toujours tons entiers (T–T–T½–T–T½), sérénité, couleur orientale/folk." },

  // ── Topic 3 : La gamme octatonique — 12 questions ────────────────────────

  { q: "Combien de notes contient la gamme octatonique ?", opts: ["6 notes", "7 notes", "8 notes", "9 notes"], a: 2, fb: "La gamme octatonique ('octa' = 8) contient 8 notes par octave. Exemple : Do–Ré–Mib–Fa–Fa#–Sol#–La–Si–Do. Elle alterne ton et demi-ton (ou demi-ton et ton selon la version)." },

  { q: "Quel est le principe de construction de la gamme octatonique ?", opts: ["Tons entiers uniquement", "Alternance ton–demi-ton (ou demi-ton–ton)", "Demi-tons uniquement", "Tierce mineure + demi-ton en alternance"], a: 1, fb: "La gamme octatonique alterne strictement ton et demi-ton (T–½T–T–½T–T–½T–T–½T) ou l'inverse (½T–T–½T–T–½T–T–½T–T). Cette symétrie crée exactement 8 notes sur l'octave." },

  { q: "Quel accord caractéristique se trouve naturellement dans la gamme octatonique ?", opts: ["L'accord augmenté", "L'accord de dominante 7e", "L'accord diminué de 7e (dim7)", "L'accord de 6te napolitaine"], a: 2, fb: "La gamme octatonique contient 3 accords diminués de 7e (dim7) : Do–Mib–Fa#–La, Ré–Fa–Sol#–Si, et Mi–Sol–La#–Do#. C'est la gamme idéale pour construire des séquences de dim7." },

  { q: "Combien de transpositions distinctes possède la gamme octatonique ?", opts: ["2 transpositions", "3 transpositions", "4 transpositions", "12 transpositions"], a: 1, fb: "La gamme octatonique n'a que 3 transpositions distinctes. Après 3 transpositions d'un demi-ton, on retrouve la même collection de notes. C'est le mode 2 de Messiaen, avec exactement 3 transpositions." },

  { q: "Quel compositeur russe a massivement utilisé la gamme octatonique dans ses ballets ?", opts: ["Sergei Rachmaninov", "Pyotr Ilyich Tchaïkovsky", "Igor Stravinsky", "Dmitri Chostakovitch"], a: 2, fb: "Igor Stravinsky est le maître de la gamme octatonique, qu'il emploie dans ses grands ballets (L'Oiseau de Feu, Pétrouchka, Le Sacre du Printemps). Elle lui confère cette couleur 'slave mystique' caractéristique." },

  { q: "Quel compositeur français a théorisé la gamme octatonique comme 'mode 2 à transpositions limitées' ?", opts: ["Claude Debussy", "Maurice Ravel", "Olivier Messiaen", "Gabriel Fauré"], a: 2, fb: "Olivier Messiaen a systématisé les gammes symétriques dans 'Technique de mon langage musical' (1944). Il a nommé la gamme octatonique 'mode 2 à transpositions limitées' — 3 transpositions possibles contre 2 pour le mode 1." },

  { q: "La gamme octatonique Do–Ré–Mib–Fa–Fa#–Sol#–La–Si contient combien d'accords diminués 7e distincts ?", opts: ["1 accord dim7", "2 accords dim7", "3 accords dim7", "4 accords dim7"], a: 2, fb: "Toute gamme octatonique contient exactement 3 accords dim7 imbriqués. Dans Do–Ré–Mib–Fa–Fa#–Sol#–La–Si : (1) Do–Mib–Fa#–La, (2) Ré–Fa–Sol#–Si, et (3) Mib–Fa#–La–Do. Ces trois accords couvrent tous les 12 sons chromatiques." },

  { q: "Quelle est la couleur sonore caractéristique de la gamme octatonique ?", opts: ["Flottement onirique sans tension", "Tension symétrique, mystère, instabilité organisée", "Sérénité, couleur orientale", "Clarté tonale diatonique"], a: 1, fb: "La gamme octatonique crée une tension symétrique particulière — les accords dim7 créent une instabilité mais de façon ordonnée. La couleur est sombre, mystérieuse, tendue — caractéristique du style slave mystique de Stravinsky et de la flamboyance de Messiaen." },

  { q: "La gamme octatonique diffère de la gamme par tons en ce que :", opts: ["La gamme octatonique a 6 notes, la gamme par tons en a 8", "La gamme octatonique alterne ton et demi-ton (8 notes), la gamme par tons n'a que des tons entiers (6 notes)", "Elles sont identiques — ce sont deux noms pour la même gamme", "La gamme octatonique vient de Russie, la gamme par tons de France"], a: 1, fb: "Différence fondamentale : gamme par tons = 6 notes, tous tons entiers, accords augmentés. Gamme octatonique = 8 notes, alternance ton/demi-ton, accords dim7. Deux couleurs très distinctes malgré leur symétrie commune." },

  { q: "Dans 'Pétrouchka' de Stravinsky, l'accord 'bitonale' (Do majeur + Fa# majeur simultanément) est possible grâce à :", opts: ["La gamme pentatonique", "La gamme par tons", "La gamme octatonique", "Le système dodécaphonique"], a: 2, fb: "L'accord 'Pétrouchka' (Do–Mi–Sol + Fa#–La#–Do#) est rendu cohérent par la gamme octatonique qui contient les deux ensembles de notes simultanément. La symétrie octatonique permet cette bitonalité caractéristique." },

  { q: "Pourquoi l'accord diminué de 7e (dim7) est-il particulièrement ambiguë tonalement ?", opts: ["Parce qu'il contient un triton", "Parce qu'il est composé de tierces mineures égales — il peut résoudre vers 4 tonalités différentes", "Parce qu'il est trop dissonant pour résoudre", "Parce qu'il n'appartient à aucune gamme"], a: 1, fb: "L'accord dim7 est composé de 4 tierces mineures superposées (Do–Mib–Fa#–La). Comme toutes ses tierces sont égales, il est parfaitement symétrique et peut résoudre vers 4 tonalités majeures ou mineures différentes — d'où son ambiguïté tonale extrême." },

  { q: "La gamme octatonique est appelée 'mode 2' par Messiaen car :", opts: ["C'est la deuxième gamme qu'il a inventée", "C'est la gamme avec 2 transpositions distinctes", "C'est le deuxième mode dans sa classification des modes à transpositions limitées (après la gamme par tons)", "C'est la gamme qui commence sur le 2e degré"], a: 2, fb: "Messiaen a numéroté ses modes selon leur complexité et leur nombre de transpositions. Le mode 1 (2 transpositions) = gamme par tons. Le mode 2 (3 transpositions) = gamme octatonique. La numérotation suit un ordre logique dans son système." },

  // ── Topic 4 : La gamme pentatonique — 12 questions ───────────────────────

  { q: "Combien de notes contient la gamme pentatonique ?", opts: ["4 notes", "5 notes", "6 notes", "7 notes"], a: 1, fb: "La gamme pentatonique ('penta' = 5) contient 5 notes. La version la plus courante sur Do est : Do–Ré–Mi–Sol–La. Elle est obtenue en supprimant le Fa et le Si de la gamme de Do majeur." },

  { q: "Qu'est-ce qui caractérise la gamme pentatonique par rapport à la gamme majeure ?", opts: ["Elle contient plus de demi-tons", "Elle ne contient aucun demi-ton — ce qui supprime toute tension directionnelle", "Elle contient un triton central", "Elle est toujours mineure"], a: 1, fb: "La gamme pentatonique majeure Do–Ré–Mi–Sol–La ne contient aucun demi-ton. L'absence de demi-ton signifie l'absence de sensible et de triton — donc pas de tension directionnelle vers une résolution. Le son est serein, ouvert." },

  { q: "Quelle note est absente de la pentatonique Do–Ré–Mi–Sol–La par rapport à Do majeur ?", opts: ["Ré et Sol", "Fa et Si", "Mi et La", "Sol et Do"], a: 1, fb: "La gamme de Do majeur est Do–Ré–Mi–Fa–Sol–La–Si–Do. En supprimant le Fa et le Si (les deux notes qui forment le triton et créent la tension sensible-tonique), on obtient la pentatonique Do–Ré–Mi–Sol–La." },

  { q: "Pourquoi la gamme pentatonique est-elle universelle — présente dans presque toutes les cultures musicales ?", opts: ["Parce que les Grecs anciens l'ont imposée au monde", "Parce qu'elle est facile à jouer sur n'importe quel instrument", "Parce que l'absence de demi-ton la rend naturellement consonante et universellement accessible", "Parce que les 5 doigts de la main correspondent aux 5 notes"], a: 2, fb: "L'absence de demi-ton dans la gamme pentatonique la rend naturellement agréable à l'oreille humaine — aucune note ne crée de tension vers une résolution. C'est cette propriété de consonance naturelle qui explique sa présence dans les musiques d'Afrique, d'Asie, d'Amérique et d'Europe." },

  { q: "La gamme pentatonique est utilisée dans la musique impressionniste pour évoquer :", opts: ["La complexité de l'harmonie romantique allemande", "La couleur orientale, exotique ou ancienne (gamelan, musique chinoise)", "Le contrepoint baroque rigoureux", "La danse folklorique irlandaise"], a: 1, fb: "Debussy a découvert le gamelan javanais à l'Exposition Universelle de 1889. Fasciné par la couleur pentatonique de cette musique, il l'a intégrée dans son langage impressionniste pour évoquer l'Orient, le rêve et l'exotisme." },

  { q: "Quel est le rapport entre la pentatonique et le jazz ?", opts: ["Le jazz évite systématiquement la pentatonique", "La pentatonique (mineure surtout) est l'une des bases du jazz et du blues", "Le jazz utilise uniquement la pentatonique — jamais les autres gammes", "La pentatonique est exclusive à la musique classique"], a: 1, fb: "La pentatonique mineure (Do–Mib–Fa–Sol–Sib) est au cœur du blues et du jazz. Elle permet de jouer 'à l'oreille' sur n'importe quel accord sans dissonance — d'où son omniprésence dans les solos d'improvisation jazz et blues." },

  { q: "La pentatonique mineure sur La est :", opts: ["La–Si–Do–Mi–Fa#", "La–Do–Ré–Mi–Sol", "La–Sib–Do–Réb–Mib", "La–Si–Ré–Mi–Sol#"], a: 1, fb: "La pentatonique mineure sur La est La–Do–Ré–Mi–Sol. Structure : T½–T–T–T½–T. Elle correspond à la pentatonique majeure de Do (Do–Ré–Mi–Sol–La) mais lue depuis La — les deux partagent exactement les mêmes notes." },

  { q: "Dans 'Voiles' de Debussy, la section centrale utilise la pentatonique pour créer :", opts: ["Un contraste de couleur avec la gamme par tons de la section principale", "Une tension maximale avant la résolution finale", "Un retour à la tonalité de Do majeur", "Un effet de fugue baroque"], a: 0, fb: "'Voiles' est construit sur la gamme par tons (Do–Ré–Mi–Fa#–Sol#–La#) dans les sections A. La section centrale (B) utilise la pentatonique (Sol#–La#–Do–Ré–Mi) — ce contraste de couleur est un coup de génie : deux gammes sans demi-ton, deux couleurs radicalement différentes." },

  { q: "La pentatonique est souvent utilisée dans la musique folk et les chants traditionnels car :", opts: ["Elle est plus facile à mémoriser avec 5 notes seulement", "Son absence de demi-ton permet une intonation plus simple et une adaptabilité à différentes voix", "Les musiciens traditionnels ignoraient les gammes à 7 notes", "Elle correspond exactement aux modes grégoriens"], a: 1, fb: "L'absence de demi-ton dans la pentatonique la rend particulièrement adaptée au chant traditionnel : pas de tension d'intonation sur les demi-tons, adaptable à différents registres, naturellement consonante entre plusieurs voix." },

  { q: "Combien de transpositions distinctes possède la gamme pentatonique ?", opts: ["5 transpositions distinctes", "7 transpositions distinctes", "12 transpositions distinctes", "2 transpositions distinctes"], a: 2, fb: "La gamme pentatonique a 12 transpositions distinctes — elle n'est pas un 'mode à transpositions limitées'. Contrairement à la gamme par tons (2) ou à l'octatonique (3), la pentatonique peut être transposée 12 fois sans revenir à elle-même avant l'octave." },

  { q: "Quel est l'accord de dominante dans la gamme pentatonique Do–Ré–Mi–Sol–La ?", opts: ["Sol–Si–Ré (V majeur)", "Sol–Sib–Ré (V mineur)", "Il n'y a pas d'accord de dominante au sens fonctionnel — Si et Fa sont absents", "Sol–La–Ré (accord de quinte ajoutée)"], a: 2, fb: "La gamme pentatonique ne contient pas de Si (sensible) ni de Fa. Or l'accord de dominante V7 (Sol–Si–Ré–Fa) nécessite ces deux notes. Sans sensible, pas de tension fonctionnelle vers I — c'est précisément ce qui donne à la pentatonique son caractère sans résolution." },

  { q: "Quelle différence fondamentale existe entre la pentatonique et la gamme par tons sur le plan de la couleur ?", opts: ["La pentatonique sonne plus 'moderne' que la gamme par tons", "La gamme par tons crée le flottement/mystère augmenté, la pentatonique crée la sérénité/clarté sans tension", "La pentatonique est plus dissonante que la gamme par tons", "Il n'y a pas de différence de couleur — les deux sont 'impressionnistes'"], a: 1, fb: "Gamme par tons : flottement mystérieux et dissolution tonale (accords augmentés, aucune note directrice). Pentatonique : sérénité et clarté sans tension (consonances naturelles, couleur folk ou orientale). Deux couleurs distinctes malgré l'absence commune de demi-ton." },

  // ── Topic 5 : Modes de Messiaen et modal interchange — 12 questions ───────

  { q: "Qu'est-ce qu'un 'mode à transpositions limitées' selon Messiaen ?", opts: ["Un mode qui ne peut pas être transposé", "Un mode dont les transpositions successives reproduisent des collections de notes identiques avant d'avoir parcouru tous les 12 demi-tons", "Un mode utilisé uniquement dans la liturgie", "Un mode qui se limite à 5 notes"], a: 1, fb: "Un mode à transpositions limitées est une gamme dont la symétrie interne fait que certaines transpositions reproduisent exactement la même collection de notes. Ex. : la gamme par tons sur Do et sur Ré sont deux gammes distinctes, mais sur Mi elles reviennent à Do — donc seulement 2 transpositions réelles." },

  { q: "Combien de modes à transpositions limitées Messiaen a-t-il répertoriés dans son traité de 1944 ?", opts: ["3 modes", "5 modes", "7 modes", "12 modes"], a: 2, fb: "Messiaen a répertorié 7 modes à transpositions limitées dans 'Technique de mon langage musical' (1944). Chaque mode est caractérisé par sa structure d'intervalles, son nombre de transpositions et sa 'couleur' particulière." },

  { q: "Le mode 1 de Messiaen a 2 transpositions et le mode 2 en a 3. Que signifie ce nombre croissant ?", opts: ["Que le mode 2 est plus complexe et plus dissonant", "Que plus il y a de transpositions, moins la symétrie interne est forte", "Plus un mode a de transpositions distinctes, plus il se rapproche d'une gamme ordinaire — la symétrie s'affaiblit", "Que le mode 2 couvre plus de tonalités que le mode 1"], a: 2, fb: "La logique est inverse de ce qu'on croit : moins de transpositions = plus de symétrie interne (mode 1 : 2 transpositions, symétrie maximale). Plus de transpositions = symétrie plus faible. Une gamme ordinaire a 12 transpositions distinctes — aucune symétrie interne particulière." },

  { q: "Quel est l'effet recherché par Messiaen quand il utilise les modes à transpositions limitées dans ses œuvres ?", opts: ["Maximiser la tension harmonique pour une résolution dramatique", "Créer une couleur unique et inimitable par la symétrie interne du mode", "Retrouver le contrepoint baroque de Bach", "Rendre la musique accessible au grand public"], a: 1, fb: "Messiaen cherchait explicitement la 'couleur' harmonique — chaque mode à transpositions limitées possède une couleur unique et reconnaissable. Sa foi catholique l'a conduit à associer des couleurs visuelles précises à chaque mode (synesthésie)." },

  { q: "Qu'est-ce que le 'modal interchange' (emprunt modal) ?", opts: ["Changer de mode dans une même pièce — passer d'un mode à un autre", "Emprunter un accord à un mode parallèle ou à la gamme éolienne (mineure naturelle) tout en restant dans la même tonalité", "Transposer toute la pièce dans un autre mode", "Utiliser des accords de deux tonalités différentes simultanément (bitonalité)"], a: 1, fb: "Le modal interchange (emprunt modal) consiste à emprunter ponctuellement un accord à une autre gamme basée sur la même tonique. En Do majeur, on peut emprunter IVm (Fa mineur) du Do mineur, bVI (Lab) ou bVII (Sib) du Do éolien — sans quitter Do comme centre tonal." },

  { q: "L'accord IVm emprunté en Do majeur est :", opts: ["Fa–La–Do (Fa majeur)", "Fa–Lab–Do (Fa mineur)", "Fa–La–Do# (Fa augmenté)", "Fa–Lab–Dob (Fa diminué)"], a: 1, fb: "IVm en Do majeur = accord mineur sur le 4e degré = Fa–Lab–Do. Cet accord s'emprunte au Do mineur (ou éolien) où le La est bémolisé (Lab). C'est l'un des emprunts modaux les plus expressifs et les plus fréquents en musique pop et jazz." },

  { q: "L'accord bVII en Do majeur (Sib–Ré–Fa) s'emprunte au mode :", opts: ["Do dorien", "Do phrygien", "Do mixolydien", "Do lydien"], a: 2, fb: "Le mode mixolydien sur Do (Do–Ré–Mi–Fa–Sol–La–Sib) est identique à Do majeur mais avec un Sib au lieu de Si. L'accord bVII (Sib majeur = Sib–Ré–Fa) est naturel dans le mode mixolydien. Son effet est caractéristique du rock et de la musique modale." },

  { q: "Quel est l'effet typique de l'accord bVI (Lab en Do majeur) dans une progression en Do ?", opts: ["Il clarifie la tonalité de Do", "Il crée une couleur romantique et expressive — un emprunt très saisissant", "Il équivaut à une dominante secondaire", "Il annonce toujours une modulation"], a: 1, fb: "L'accord bVI (Lab–Do–Mib) emprunté au Do mineur/éolien crée une couleur romantique soudaine et très expressive. Sa couleur 'inattendue' dans un contexte majeur est très saisissante — fréquent chez Schubert et dans la pop (ex. : le 'flat-six chord' des ballades rock)." },

  { q: "La progression I–bVI–bVII–I en Do majeur utilise des emprunts aux modes :", opts: ["Dorien et phrygien uniquement", "Éolien (pour bVI et bVII) et mixolydien (pour bVII)", "Lydien et locrien", "Aucun emprunt modal — ce sont des accords diatoniques de Do majeur"], a: 1, fb: "En Do majeur : bVI = Lab (emprunté à Do éolien qui a Lab), bVII = Sib (emprunté à Do mixolydien qui a Sib). Cette progression (Do–Lab–Sib–Do) est très fréquente en rock et pop — elle combine deux saveurs modales distinctes." },

  { q: "Pourquoi le modal interchange ne crée-t-il pas une modulation ?", opts: ["Parce qu'il n'utilise que des accords majeurs", "Parce que la tonique reste la même — l'emprunt est ponctuel, pas structurel", "Parce qu'il n'utilise pas d'accord de dominante", "Parce qu'il dure toujours moins d'une mesure"], a: 1, fb: "Le modal interchange est un emprunt ponctuel — la tonique ne change pas. En Do majeur, emprunter Lab (bVI) crée une couleur, mais Do reste le centre tonal. Une modulation implique un changement de centre tonal confirmé par une cadence dans la nouvelle tonalité." },

  { q: "Le mode 3 de Messiaen a 4 transpositions et 9 notes. Sa structure est :", opts: ["T–T–T–T–T–T–T–T (8 tons entiers)", "T–½T–½T répété 3 fois (groupes de 3 notes)", "½T–T–½T–T répété 4 fois", "T–½T–T–T–½T–T–T–½T–T"], a: 1, fb: "Le mode 3 de Messiaen est construit sur des groupes de 3 notes : T–½T–½T, répété 3 fois pour couvrir l'octave. Sa structure est Do–Ré–Mib–Mi–Fa#–Sol–Sol#–La#–Si. Il a 4 transpositions distinctes et une couleur plus chromatique et dense que les modes 1 et 2." },

  { q: "Quelle est la propriété commune à tous les modes à transpositions limitées de Messiaen ?", opts: ["Ils contiennent tous exactement 6 notes", "Ils ont tous une symétrie interne qui fait que certaines transpositions produisent la même collection de notes", "Ils sont tous dérivés de la gamme majeure par suppression de notes", "Ils sont tous construits sur des tritons"], a: 1, fb: "La propriété fondamentale commune à tous les modes à transpositions limitées est leur symétrie interne. Cette symétrie fait que, après un certain nombre de transpositions (moins de 12), on retrouve exactement la même collection de hauteurs. C'est le critère qui les distingue des gammes 'ordinaires'." },
];

const questionsEn: Question[] = [
  // ── Topic 1: Planing (parallelism) — 12 questions ────────────────────────
  { q: "What is planing in impressionist harmony?", opts: ["A technique for resolving dissonances", "The sliding of a complete chord in parallel motion without functional resolution", "A whole-tone scale", "A characteristic V–I progression"], a: 1, fb: "Planing is the sliding of a complete chord (with all its voices) in parallel motion. The chord's color shifts without tensions resolving — the effect is of a 'sound block that slides.'" },
  { q: "What is the difference between diatonic planing and chromatic planing?", opts: ["Diatonic planing uses semitones, chromatic planing uses whole tones", "Diatonic planing preserves the same chord type on each scale degree, chromatic planing transposes the exact same chord", "Diatonic planing is Ravel's technique, chromatic planing is Debussy's", "There is no difference — the two terms designate the same technique"], a: 1, fb: "Diatonic planing: chords change quality according to the scale degrees (e.g., sixth chords in parallel thirds). Chromatic planing: the exact same chord (same quality) slides chromatically — all voices move by the same interval." },
  { q: "In chromatic planing, what happens to the chords as they move?", opts: ["They change quality (major → minor according to the degree)", "They keep exactly the same interval structure — only the pitch changes", "They lose their fifths to avoid parallels", "They resolve to the tonic with each displacement"], a: 1, fb: "In chromatic planing, the chord is transposed exactly: if it is a dominant seventh chord, it remains a dominant seventh chord at each step. The quality is preserved, only the pitch varies." },
  { q: "Why are parallel fifths and octaves tolerated in planing?", opts: ["Because they are rare in planing", "Because planing works precisely on this parallel sound block effect — it is intentional, not an error", "Because Debussy was ignorant of counterpoint rules", "Because they are compensated by resolved dissonances"], a: 1, fb: "Planing deliberately contradicts the rules of Classical counterpoint. Parallel fifths create the characteristic 'block' effect — the sound slides as a single object. It is an aesthetic choice, not negligence." },
  { q: "Which composer is the undisputed master of Impressionist planing?", opts: ["César Franck", "Claude Debussy", "Johannes Brahms", "Ludwig van Beethoven"], a: 1, fb: "Claude Debussy is the creator and master of Impressionist planing. His piece 'La Cathédrale engloutie' and his preludes abound with chords in parallel motion that create color effects without functional resolution." },
  { q: "How do you analyze planing — with the functions T/SD/D or otherwise?", opts: ["With the Classical T/SD/D functions, like any tonal chord", "By color and register: identify the starting chord, note the movement, describe the sonic effect", "By Schenkerian analysis only", "Planing cannot be analyzed — it is improvisation"], a: 1, fb: "Functional analysis (T/SD/D) does not apply to planing: there is no tension-resolution in the Classical sense. Analysis is done by color (chord type), register (low/high) and effect (floating, opacity, clarity)." },
  { q: "In diatonic planing, if we start on I (major chord), the chord on II will be:", opts: ["Always major", "Minor, because II is minor in the major scale", "Diminished, because II is diminished", "Augmented, because the scale requires it"], a: 1, fb: "In diatonic planing, chords follow the diatonic quality of each degree. In C major, II is D minor (D–F–A). Diatonic planing preserves the key signature — chords change quality according to the degree." },
  { q: "Debussy's piece 'La Cathédrale engloutie' makes massive use of:", opts: ["Classical secondary dominants", "Stacked fourth chords", "Chords in parallel planing to evoke bells underwater", "Dodecaphonic scales"], a: 2, fb: "'La Cathédrale engloutie' uses blocks of chords (often fifths and fourths) in parallel motion to simulate bell resonances. The planing creates the characteristic aquatic immersion effect of the piece." },
  { q: "Planing appeared primarily in which musical movement?", opts: ["Baroque counterpoint", "German Romantic harmony (Brahms, Wagner)", "French Impressionism (Debussy, Ravel)", "Viennese dodecaphonism (Schoenberg)"], a: 2, fb: "Planing is a characteristic technique of French Impressionism, developed by Debussy and Ravel at the end of the 19th and beginning of the 20th century. It draws inspiration from Japanese music (gamelan) and Oriental prints." },
  { q: "In planing, what replaces the Classical harmonic function?", opts: ["Strict 4-voice counterpoint", "The sonic color, register, and timbre of the chord", "The progression by tritones", "The strict alternation of minor/major"], a: 1, fb: "In Impressionist harmony, color (chord quality: major, 7th, 9th), register (low, medium, high), and timbre (open or closed position) replace the tension-resolution logic of the tonal system." },
  { q: "A Maj7 chord in chromatic planing that rises by a semitone becomes:", opts: ["A minor chord", "The same type of Maj7 chord but a semitone higher", "A diminished chord", "A dominant seventh chord"], a: 1, fb: "In chromatic planing, the chord structure is preserved. C Maj7 (C–E–G–B) transposed a semitone higher gives Db Maj7 (Db–F–Ab–C). Same interval structure, different pitch." },
  { q: "What is the typical auditory sensation of planing?", opts: ["Growing tension toward a strong resolution", "A colorful sliding without functional direction — like a sonic watercolor", "A reinforcement of the main key", "A dissolution toward silence"], a: 1, fb: "Planing creates a sensation of sliding or floating — the chord moves like a single object in sonic space. There is no functional direction toward a resolution, just a shift of color." },

  // ── Topic 2: The whole-tone scale — 12 questions ─────────────────────────
  { q: "How many notes does the whole-tone scale contain?", opts: ["5 notes", "6 notes", "7 notes", "8 notes"], a: 1, fb: "The whole-tone scale contains 6 notes, all separated by a whole step (2 semitones). Example: C–D–E–F#–G#–A# (then back to C). There are only 2 distinct whole-tone scales (all others are transpositions identical to one or the other)." },
  { q: "What is the interval between each note of the whole-tone scale?", opts: ["A semitone (½T)", "A whole tone (T)", "A minor third (T½)", "A tritone"], a: 1, fb: "Each degree of the whole-tone scale is separated from the next by a whole tone (2 semitones). This is what gives this scale its total symmetry and the absence of a leading tone." },
  { q: "Why does the whole-tone scale not contain a leading tone?", opts: ["By a construction error", "Because all intervals are identical (whole tones) — no semitone creates directional tension", "Because it is pentatonic", "Because it starts on C"], a: 1, fb: "The leading tone works through the semitone that creates tension toward the tonic. In the whole-tone scale, all intervals are whole tones — no semitone, therefore no directional tension, therefore no leading tone. The floating is total." },
  { q: "What type of chord is naturally produced by the whole-tone scale?", opts: ["Major triad (major third + perfect fifth)", "Augmented chord (major third + major third)", "Diminished chord (minor third + minor third)", "Dominant seventh chord"], a: 1, fb: "The whole-tone scale produces augmented chords: by stacking thirds on the degrees of the whole-tone scale, one systematically obtains superimposed major thirds. Ex.: C–E–G# = augmented chord." },
  { q: "How many distinct transpositions does the whole-tone scale have?", opts: ["6 distinct transpositions", "7 distinct transpositions", "2 distinct transpositions only", "12 distinct transpositions"], a: 2, fb: "The whole-tone scale can only be transposed in 2 distinct ways before returning to itself. Ex.: C–D–E–F#–G#–A# and Db–Eb–F–G–A–B. All other 'transpositions' reproduce one of these two scales." },
  { q: "Which famous prelude by Debussy is entirely built on the whole-tone scale?", opts: ["Clair de Lune", "La Fille aux cheveux de lin", "Voiles", "La Cathédrale engloutie"], a: 2, fb: "'Voiles' (Préludes Book I, 1909) is the best-known example of a piece entirely built on the whole-tone scale. The central section uses the pentatonic scale, creating a striking color contrast." },
  { q: "The whole-tone scale C–D–E–F#–G#–A# produces which chord on C?", opts: ["C major (C–E–G)", "C augmented (C–E–G#)", "C minor (C–Eb–G)", "C diminished (C–Eb–Gb)"], a: 1, fb: "By building a chord on C in the whole-tone scale (C–D–E–F#–G#–A#), one takes C, E (major third), G# (additional major third) = C augmented. All chords in this scale are augmented." },
  { q: "What is the characteristic sonic color of the whole-tone scale?", opts: ["Strong tension, destabilizing, urgent resolution", "Floating, tonal dissolution, dreamlike mystery", "Diatonic clarity, solid structure", "Rhythmic violence, Slavic color"], a: 1, fb: "The whole-tone scale creates total tonal floating — without a leading tone, without a semitone, the ear cannot orient itself toward any tonic. The effect is dreamlike, mysterious, dissolved — exactly the Impressionist aesthetic of Debussy." },
  { q: "The whole-tone scale is also called Messiaen's mode __.", opts: ["Mode 2", "Mode 3", "Mode 1", "Mode 4"], a: 2, fb: "Messiaen systematized symmetrical scales in his treatise 'Technique de mon langage musical' (1944). The whole-tone scale is his Mode 1 — the simplest, with only 2 possible transpositions." },
  { q: "Between the whole-tone scale on C and the whole-tone scale on Db, how many notes are common?", opts: ["No notes in common", "3 common notes", "All notes — they are the same", "Only 1 common note"], a: 0, fb: "The two distinct whole-tone scales (C–D–E–F#–G#–A# and Db–Eb–F–G–A–B) have no notes in common (enharmonics aside). Together they share all 12 semitones." },
  { q: "Why can the whole-tone scale be said to be 'perfectly symmetrical'?", opts: ["Because it has 7 degrees like the major scale", "Because all its intervals are identical — it can be read from any degree and give the same scale", "Because it contains a tritone at its center", "Because it alternates tones and semitones"], a: 1, fb: "The perfect symmetry of the whole-tone scale comes from the uniformity of its intervals. Regardless of the starting note within the scale, the interval succession is identical (T–T–T–T–T–T). This is a property the major scale does not have." },
  { q: "In a pedagogical context, how does the whole-tone scale differ from the pentatonic scale?", opts: ["They are interchangeable — same sonic effect", "The whole-tone scale has 6 notes, total floating, augmented chords; the pentatonic has 5 notes, serenity, no dominant chord", "The whole-tone scale is major, the pentatonic is minor", "The whole-tone scale comes from Asia, the pentatonic from France"], a: 1, fb: "Essential distinction: whole-tone scale = 6 notes, whole tones only, tonal floating, augmented chords. Pentatonic = 5 notes, no semitones but not always whole tones (T–T–T½–T–T½), serenity, Oriental/folk color." },

  // ── Topic 3: The octatonic scale — 12 questions ───────────────────────────
  { q: "How many notes does the octatonic scale contain?", opts: ["6 notes", "7 notes", "8 notes", "9 notes"], a: 2, fb: "The octatonic scale ('octa' = 8) contains 8 notes per octave. Example: C–D–Eb–F–F#–G#–A–B–C. It alternates whole tone and semitone (or semitone and whole tone depending on the version)." },
  { q: "What is the construction principle of the octatonic scale?", opts: ["Whole tones only", "Alternation of whole tone–semitone (or semitone–whole tone)", "Semitones only", "Minor third + semitone alternating"], a: 1, fb: "The octatonic scale strictly alternates whole tone and semitone (T–½T–T–½T–T–½T–T–½T) or the reverse (½T–T–½T–T–½T–T–½T–T). This symmetry creates exactly 8 notes within the octave." },
  { q: "Which characteristic chord is naturally found in the octatonic scale?", opts: ["The augmented chord", "The dominant seventh chord", "The diminished seventh chord (dim7)", "The Neapolitan sixth chord"], a: 2, fb: "The octatonic scale contains 3 diminished seventh chords (dim7): C–Eb–F#–A, D–F–G#–B, and Eb–F#–A–C. It is the ideal scale for building dim7 sequences." },
  { q: "How many distinct transpositions does the octatonic scale have?", opts: ["2 transpositions", "3 transpositions", "4 transpositions", "12 transpositions"], a: 1, fb: "The octatonic scale has only 3 distinct transpositions. After 3 transpositions by a semitone, one returns to the same collection of notes. It is Messiaen's Mode 2, with exactly 3 transpositions." },
  { q: "Which Russian composer massively used the octatonic scale in his ballets?", opts: ["Sergei Rachmaninov", "Pyotr Ilyich Tchaikovsky", "Igor Stravinsky", "Dmitri Shostakovich"], a: 2, fb: "Igor Stravinsky is the master of the octatonic scale, which he employs in his great ballets (The Firebird, Petrushka, The Rite of Spring). It gives him that characteristic 'mystic Slavic' color." },
  { q: "Which French composer theorized the octatonic scale as 'Mode 2 of limited transposition'?", opts: ["Claude Debussy", "Maurice Ravel", "Olivier Messiaen", "Gabriel Fauré"], a: 2, fb: "Olivier Messiaen systematized symmetrical scales in 'Technique de mon langage musical' (1944). He named the octatonic scale 'Mode 2 of limited transposition' — 3 possible transpositions versus 2 for Mode 1." },
  { q: "The octatonic scale C–D–Eb–F–F#–G#–A–B contains how many distinct diminished seventh chords?", opts: ["1 dim7 chord", "2 dim7 chords", "3 dim7 chords", "4 dim7 chords"], a: 2, fb: "Every octatonic scale contains exactly 3 interlocking dim7 chords. In C–D–Eb–F–F#–G#–A–B: (1) C–Eb–F#–A, (2) D–F–G#–B, and (3) Eb–F#–A–C. These three chords cover all 12 chromatic pitches." },
  { q: "What is the characteristic sonic color of the octatonic scale?", opts: ["Dreamlike floating without tension", "Symmetrical tension, mystery, organized instability", "Serenity, Oriental color", "Diatonic tonal clarity"], a: 1, fb: "The octatonic scale creates a particular symmetrical tension — dim7 chords create instability but in an ordered way. The color is dark, mysterious, tense — characteristic of Stravinsky's mystic Slavic style and Messiaen's flamboyance." },
  { q: "The octatonic scale differs from the whole-tone scale in that:", opts: ["The octatonic scale has 6 notes, the whole-tone scale has 8", "The octatonic scale alternates whole tone and semitone (8 notes), the whole-tone scale has only whole tones (6 notes)", "They are identical — two names for the same scale", "The octatonic scale comes from Russia, the whole-tone scale from France"], a: 1, fb: "Fundamental difference: whole-tone scale = 6 notes, all whole tones, augmented chords. Octatonic scale = 8 notes, alternating whole tone/semitone, dim7 chords. Two very distinct colors despite their shared symmetry." },
  { q: "In Stravinsky's 'Petrushka', the 'bitonal' chord (C major + F# major simultaneously) is possible thanks to:", opts: ["The pentatonic scale", "The whole-tone scale", "The octatonic scale", "The dodecaphonic system"], a: 2, fb: "The 'Petrushka chord' (C–E–G + F#–A#–C#) is rendered coherent by the octatonic scale which simultaneously contains both sets of notes. The octatonic symmetry enables this characteristic bitonality." },
  { q: "Why is the diminished seventh chord (dim7) particularly tonally ambiguous?", opts: ["Because it contains a tritone", "Because it is composed of equal minor thirds — it can resolve toward 4 different keys", "Because it is too dissonant to resolve", "Because it belongs to no scale"], a: 1, fb: "The dim7 chord is composed of 4 superimposed minor thirds (C–Eb–F#–A). Since all its thirds are equal, it is perfectly symmetrical and can resolve toward 4 different major or minor keys — hence its extreme tonal ambiguity." },
  { q: "The octatonic scale is called 'Mode 2' by Messiaen because:", opts: ["It is the second scale he invented", "It is the scale with 2 distinct transpositions", "It is the second mode in his classification of modes of limited transposition (after the whole-tone scale)", "It is the scale that starts on the 2nd degree"], a: 2, fb: "Messiaen numbered his modes according to their complexity and number of transpositions. Mode 1 (2 transpositions) = whole-tone scale. Mode 2 (3 transpositions) = octatonic scale. The numbering follows a logical order in his system." },

  // ── Topic 4: The pentatonic scale — 12 questions ─────────────────────────
  { q: "How many notes does the pentatonic scale contain?", opts: ["4 notes", "5 notes", "6 notes", "7 notes"], a: 1, fb: "The pentatonic scale ('penta' = 5) contains 5 notes. The most common version on C is: C–D–E–G–A. It is obtained by removing F and B from the C major scale." },
  { q: "What characterizes the pentatonic scale compared to the major scale?", opts: ["It contains more semitones", "It contains no semitone — which eliminates any directional tension", "It contains a central tritone", "It is always minor"], a: 1, fb: "The major pentatonic scale C–D–E–G–A contains no semitone. The absence of semitone means the absence of leading tone and tritone — so no directional tension toward a resolution. The sound is serene, open." },
  { q: "Which note is absent from the pentatonic C–D–E–G–A compared to C major?", opts: ["D and G", "F and B", "E and A", "G and C"], a: 1, fb: "The C major scale is C–D–E–F–G–A–B–C. By removing F and B (the two notes that form the tritone and create the leading-tone-to-tonic tension), one obtains the pentatonic C–D–E–G–A." },
  { q: "Why is the pentatonic scale universal — present in almost all musical cultures?", opts: ["Because the ancient Greeks imposed it on the world", "Because it is easy to play on any instrument", "Because the absence of semitone makes it naturally consonant and universally accessible", "Because the 5 fingers of the hand correspond to the 5 notes"], a: 2, fb: "The absence of semitone in the pentatonic scale makes it naturally pleasant to the human ear — no note creates tension toward a resolution. It is this property of natural consonance that explains its presence in African, Asian, American, and European music." },
  { q: "The pentatonic scale is used in Impressionist music to evoke:", opts: ["The complexity of German Romantic harmony", "Oriental, exotic, or ancient color (gamelan, Chinese music)", "Strict Baroque counterpoint", "Irish folk dance"], a: 1, fb: "Debussy discovered the Javanese gamelan at the 1889 World Exhibition. Fascinated by the pentatonic color of this music, he integrated it into his Impressionist language to evoke the Orient, dreams, and exoticism." },
  { q: "What is the relationship between the pentatonic scale and jazz?", opts: ["Jazz systematically avoids the pentatonic scale", "The pentatonic scale (especially minor) is one of the foundations of jazz and blues", "Jazz uses only the pentatonic scale — never other scales", "The pentatonic scale is exclusive to Classical music"], a: 1, fb: "The minor pentatonic scale (C–Eb–F–G–Bb) is at the heart of blues and jazz. It allows playing 'by ear' on any chord without dissonance — hence its omnipresence in jazz and blues improvisation solos." },
  { q: "The minor pentatonic on A is:", opts: ["A–B–C–E–F#", "A–C–D–E–G", "A–Bb–C–Db–Eb", "A–B–D–E–G#"], a: 1, fb: "The minor pentatonic on A is A–C–D–E–G. Structure: T½–T–T–T½–T. It corresponds to the C major pentatonic (C–D–E–G–A) but read from A — the two share exactly the same notes." },
  { q: "In Debussy's 'Voiles', the central section uses the pentatonic to create:", opts: ["A color contrast with the whole-tone scale of the main section", "Maximum tension before the final resolution", "A return to C major tonality", "A Baroque fugue effect"], a: 0, fb: "'Voiles' is built on the whole-tone scale (C–D–E–F#–G#–A#) in the A sections. The central section (B) uses the pentatonic scale (G#–A#–C–D–E) — this color contrast is a stroke of genius: two scales without semitones, two radically different colors." },
  { q: "The pentatonic scale is often used in folk music and traditional songs because:", opts: ["It is easier to memorize with only 5 notes", "Its absence of semitone allows simpler intonation and adaptability to different voices", "Traditional musicians were ignorant of 7-note scales", "It corresponds exactly to the Gregorian modes"], a: 1, fb: "The absence of semitone in the pentatonic scale makes it particularly suited to traditional singing: no intonation tension on semitones, adaptable to different registers, naturally consonant between multiple voices." },
  { q: "How many distinct transpositions does the pentatonic scale have?", opts: ["5 distinct transpositions", "7 distinct transpositions", "12 distinct transpositions", "2 distinct transpositions"], a: 2, fb: "The pentatonic scale has 12 distinct transpositions — it is not a 'mode of limited transposition'. Unlike the whole-tone scale (2) or the octatonic (3), the pentatonic can be transposed 12 times without returning to itself before the octave." },
  { q: "What is the dominant chord in the pentatonic scale C–D–E–G–A?", opts: ["G–B–D (V major)", "G–Bb–D (V minor)", "There is no dominant chord in the functional sense — B and F are absent", "G–A–D (added fifth chord)"], a: 2, fb: "The pentatonic scale does not contain B (leading tone) or F. However, the dominant chord V7 (G–B–D–F) requires these two notes. Without a leading tone, no functional tension toward I — this is precisely what gives the pentatonic its unresolved character." },
  { q: "What fundamental difference exists between the pentatonic scale and the whole-tone scale in terms of color?", opts: ["The pentatonic sounds more 'modern' than the whole-tone scale", "The whole-tone scale creates floating/augmented mystery, the pentatonic creates serenity/clarity without tension", "The pentatonic is more dissonant than the whole-tone scale", "There is no color difference — both are 'Impressionist'"], a: 1, fb: "Whole-tone scale: mysterious floating and tonal dissolution (augmented chords, no leading tone). Pentatonic: serenity and clarity without tension (natural consonances, folk or Oriental color). Two distinct colors despite the common absence of semitone." },

  // ── Topic 5: Messiaen's modes and modal interchange — 12 questions ─────────
  { q: "What is a 'mode of limited transposition' according to Messiaen?", opts: ["A mode that cannot be transposed", "A mode whose successive transpositions reproduce identical note collections before cycling through all 12 semitones", "A mode used only in liturgy", "A mode limited to 5 notes"], a: 1, fb: "A mode of limited transposition is a scale whose internal symmetry causes certain transpositions to reproduce exactly the same note collection. Ex.: the whole-tone scale on C and on D are two distinct scales, but on E it returns to C — therefore only 2 real transpositions." },
  { q: "How many modes of limited transposition did Messiaen catalog in his 1944 treatise?", opts: ["3 modes", "5 modes", "7 modes", "12 modes"], a: 2, fb: "Messiaen catalogued 7 modes of limited transposition in 'Technique de mon langage musical' (1944). Each mode is characterized by its interval structure, its number of transpositions, and its particular 'color.'" },
  { q: "Mode 1 of Messiaen has 2 transpositions and Mode 2 has 3. What does this increasing number mean?", opts: ["That Mode 2 is more complex and more dissonant", "That the more transpositions, the weaker the internal symmetry", "The more distinct transpositions a mode has, the closer it approaches an ordinary scale — the symmetry weakens", "That Mode 2 covers more keys than Mode 1"], a: 2, fb: "The logic is the reverse of what one might think: fewer transpositions = stronger internal symmetry (Mode 1: 2 transpositions, maximum symmetry). More transpositions = weaker symmetry. An ordinary scale has 12 distinct transpositions — no particular internal symmetry." },
  { q: "What effect does Messiaen seek when he uses modes of limited transposition in his works?", opts: ["To maximize harmonic tension for a dramatic resolution", "To create a unique and inimitable color through the internal symmetry of the mode", "To recover Bach's Baroque counterpoint", "To make the music accessible to the general public"], a: 1, fb: "Messiaen explicitly sought harmonic 'color' — each mode of limited transposition has a unique and recognizable color. His Catholic faith led him to associate precise visual colors with each mode (synesthesia)." },
  { q: "What is 'modal interchange' (modal borrowing)?", opts: ["Changing mode within a piece — moving from one mode to another", "Borrowing a chord from a parallel mode or from the Aeolian scale (natural minor) while remaining in the same key", "Transposing the entire piece to another mode", "Using chords from two different keys simultaneously (bitonality)"], a: 1, fb: "Modal interchange consists of occasionally borrowing a chord from another scale based on the same tonic. In C major, one can borrow IVm (F minor) from C minor, bVI (Ab) or bVII (Bb) from C Aeolian — without leaving C as the tonal center." },
  { q: "The borrowed IVm chord in C major is:", opts: ["F–A–C (F major)", "F–Ab–C (F minor)", "F–A–C# (F augmented)", "F–Ab–Cb (F diminished)"], a: 1, fb: "IVm in C major = minor chord on the 4th degree = F–Ab–C. This chord is borrowed from C minor (or Aeolian) where A is flattened (Ab). It is one of the most expressive and frequent modal borrowings in pop and jazz music." },
  { q: "The bVII chord in C major (Bb–D–F) is borrowed from the mode:", opts: ["C Dorian", "C Phrygian", "C Mixolydian", "C Lydian"], a: 2, fb: "The Mixolydian mode on C (C–D–E–F–G–A–Bb) is identical to C major but with a Bb instead of B. The bVII chord (Bb major = Bb–D–F) is natural in the Mixolydian mode. Its effect is characteristic of rock and modal music." },
  { q: "What is the typical effect of the bVI chord (Ab in C major) in a progression in C?", opts: ["It clarifies the key of C", "It creates a Romantic and expressive color — a very striking borrowing", "It is equivalent to a secondary dominant", "It always announces a modulation"], a: 1, fb: "The bVI chord (Ab–C–Eb) borrowed from C minor/Aeolian creates a sudden Romantic and very expressive color. Its 'unexpected' color in a major context is very striking — frequent in Schubert and in pop music (e.g., the 'flat-six chord' of rock ballads)." },
  { q: "The progression I–bVI–bVII–I in C major uses borrowings from the modes:", opts: ["Dorian and Phrygian only", "Aeolian (for bVI and bVII) and Mixolydian (for bVII)", "Lydian and Locrian", "No modal borrowing — these are diatonic chords of C major"], a: 1, fb: "In C major: bVI = Ab (borrowed from C Aeolian which has Ab), bVII = Bb (borrowed from C Mixolydian which has Bb). This progression (C–Ab–Bb–C) is very frequent in rock and pop — it combines two distinct modal flavors." },
  { q: "Why does modal interchange not create a modulation?", opts: ["Because it uses only major chords", "Because the tonic remains the same — the borrowing is occasional, not structural", "Because it uses no dominant chord", "Because it always lasts less than one measure"], a: 1, fb: "Modal interchange is an occasional borrowing — the tonic does not change. In C major, borrowing Ab (bVI) creates a color, but C remains the tonal center. A modulation implies a change of tonal center confirmed by a cadence in the new key." },
  { q: "Messiaen's Mode 3 has 4 transpositions and 9 notes. Its structure is:", opts: ["T–T–T–T–T–T–T–T (8 whole tones)", "T–½T–½T repeated 3 times (groups of 3 notes)", "½T–T–½T–T repeated 4 times", "T–½T–T–T–½T–T–T–½T–T"], a: 1, fb: "Messiaen's Mode 3 is built on groups of 3 notes: T–½T–½T, repeated 3 times to cover the octave. Its structure is C–D–Eb–E–F#–G–G#–A#–B. It has 4 distinct transpositions and a more chromatic and dense color than Modes 1 and 2." },
  { q: "What property is common to all of Messiaen's modes of limited transposition?", opts: ["They all contain exactly 6 notes", "They all have an internal symmetry that causes certain transpositions to produce the same note collection", "They are all derived from the major scale by removing notes", "They are all built on tritones"], a: 1, fb: "The fundamental property common to all modes of limited transposition is their internal symmetry. This symmetry means that, after a certain number of transpositions (fewer than 12), one returns to exactly the same collection of pitches. That is the criterion that distinguishes them from 'ordinary' scales." },
];

const questionsEs: Question[] = [
  // ── Tema 1: El planing (paralelismo) — 12 preguntas ──────────────────────
  { q: "¿Qué es el planing en la armonía impresionista?", opts: ["Una técnica de resolución de disonancias", "El deslizamiento de un acorde completo en movimiento paralelo sin resolución funcional", "Una escala de tonos enteros", "Una progresión V–I característica"], a: 1, fb: "El planing es el deslizamiento de un acorde completo (con todas sus voces) en movimiento paralelo. El color del acorde se desplaza sin que las tensiones se resuelvan — el efecto es de un 'bloque sonoro que se desliza'." },
  { q: "¿Cuál es la diferencia entre el planing diatónico y el planing cromático?", opts: ["El planing diatónico usa semitonos, el cromático usa tonos enteros", "El planing diatónico conserva el mismo tipo de acorde en cada grado de la escala, el cromático transpone exactamente el mismo acorde", "El planing diatónico es propio de Ravel, el cromático de Debussy", "No hay ninguna diferencia — los dos términos designan la misma técnica"], a: 1, fb: "Planing diatónico: los acordes cambian de calidad según los grados de la escala (ej. acordes de sexta en terceras paralelas). Planing cromático: exactamente el mismo acorde (misma calidad) se desliza cromáticamente — todas las voces se mueven por el mismo intervalo." },
  { q: "En el planing cromático, ¿qué ocurre con los acordes al desplazarse?", opts: ["Cambian de calidad (mayor → menor según el grado)", "Conservan exactamente la misma estructura de intervalos — solo cambia la altura", "Pierden sus quintas para evitar los paralelismos", "Se resuelven hacia la tónica en cada desplazamiento"], a: 1, fb: "En el planing cromático, el acorde se transpone exactamente: si es un acorde de dominante con séptima, sigue siendo un acorde de dominante con séptima en cada paso. La calidad se conserva, solo varía la altura." },
  { q: "¿Por qué se toleran las quintas y octavas paralelas en el planing?", opts: ["Porque son raras en el planing", "Porque el planing funciona precisamente sobre este efecto de bloque sonoro paralelo — es intencionado, no un error", "Porque Debussy ignoraba las reglas del contrapunto", "Porque se compensan con disonancias resueltas"], a: 1, fb: "El planing contradice deliberadamente las reglas del contrapunto clásico. Las quintas paralelas crean el efecto de 'bloque' característico — el sonido se desliza como un único objeto. Es una estética, no una negligencia." },
  { q: "¿Qué compositor es el maestro indiscutible del planing impresionista?", opts: ["César Franck", "Claude Debussy", "Johannes Brahms", "Ludwig van Beethoven"], a: 1, fb: "Claude Debussy es el creador y maestro del planing impresionista. Su pieza 'La Cathédrale engloutie' y sus preludios están llenos de acordes en movimiento paralelo que crean efectos de color sin resolución funcional." },
  { q: "¿Cómo analizar el planing — con las funciones T/SD/D o de otra manera?", opts: ["Con las funciones clásicas T/SD/D, como cualquier acorde tonal", "Por color y registro: identificar el acorde de partida, anotar el movimiento, describir el efecto sonoro", "Solo por análisis schenkeriano", "No se puede analizar el planing — es improvisación"], a: 1, fb: "El análisis funcional (T/SD/D) no se aplica al planing: no hay tensión-resolución en el sentido clásico. Se analiza por color (tipo de acorde), registro (grave/agudo) y efecto (flotamiento, opacidad, claridad)." },
  { q: "En el planing diatónico, si empezamos en I (acorde mayor), el acorde en II será:", opts: ["Siempre mayor", "Menor, porque II es menor en la escala mayor", "Disminuido, porque II es disminuido", "Aumentado, porque la escala lo requiere"], a: 1, fb: "En el planing diatónico, los acordes siguen la calidad diatónica de cada grado. En Do mayor, II es Re menor (Re–Fa–La). El planing diatónico preserva la armadura — los acordes cambian de calidad según el grado." },
  { q: "La pieza 'La Cathédrale engloutie' de Debussy usa masivamente:", opts: ["Dominantes secundarias clásicas", "Acordes de cuartas apiladas", "Acordes en planing paralelo para evocar campanas bajo el agua", "Escalas dodecafónicas"], a: 2, fb: "'La Cathédrale engloutie' emplea bloques de acordes (a menudo quintas y cuartas) en movimiento paralelo para simular resonancias de campanas. El planing crea el característico efecto de inmersión acuática de la pieza." },
  { q: "El planing apareció principalmente en qué corriente musical:", opts: ["El contrapunto barroco", "La armonía romántica alemana (Brahms, Wagner)", "El impresionismo francés (Debussy, Ravel)", "El dodecafonismo vienés (Schoenberg)"], a: 2, fb: "El planing es una técnica característica del impresionismo francés, desarrollada por Debussy y Ravel a finales del siglo XIX y principios del XX. Se inspira en la música japonesa (gamelan) y las estampas orientales." },
  { q: "En el planing, ¿qué reemplaza a la función armónica clásica?", opts: ["El contrapunto estricto a 4 voces", "El color sonoro, el registro y el timbre del acorde", "La progresión por tritonos", "La alternancia estricta menor/mayor"], a: 1, fb: "En la armonía impresionista, el color (calidad del acorde: mayor, 7ª, 9ª), el registro (grave, medio, agudo) y el timbre (posición abierta o cerrada) reemplazan la lógica tensión-resolución del sistema tonal." },
  { q: "Un acorde Maj7 en planing cromático que sube un semitono se convierte en:", opts: ["Un acorde menor", "El mismo tipo de acorde Maj7 pero un semitono más alto", "Un acorde disminuido", "Un acorde de dominante séptima"], a: 1, fb: "En el planing cromático, la estructura del acorde se preserva. Do Maj7 (Do–Mi–Sol–Si) transportado un semitono más alto da Reb Maj7 (Reb–Fa–Lab–Do). Misma estructura de intervalos, altura diferente." },
  { q: "¿Cuál es la sensación auditiva típica del planing?", opts: ["Tensión creciente hacia una resolución fuerte", "Un deslizamiento colorido sin dirección funcional — como una acuarela sonora", "Un refuerzo de la tonalidad principal", "Una disolución hacia el silencio"], a: 1, fb: "El planing crea una sensación de deslizamiento o flotamiento — el acorde se mueve como un objeto único en el espacio sonoro. No hay dirección funcional hacia una resolución, solo un desplazamiento de color." },

  // ── Tema 2: La escala de tonos enteros — 12 preguntas ─────────────────────
  { q: "¿Cuántas notas contiene la escala de tonos enteros?", opts: ["5 notas", "6 notas", "7 notas", "8 notas"], a: 1, fb: "La escala de tonos enteros contiene 6 notas, todas separadas por un tono entero (2 semitonos). Ejemplo: Do–Re–Mi–Fa#–Sol#–La# (luego vuelta a Do). Solo existen 2 escalas de tonos enteros distintas (las demás son transposiciones idénticas a una u otra)." },
  { q: "¿Cuál es el intervalo entre cada nota de la escala de tonos enteros?", opts: ["Un semitono (½T)", "Un tono entero (T)", "Una tercera menor (T½)", "Un tritono"], a: 1, fb: "Cada grado de la escala de tonos enteros está separado del siguiente por un tono entero (2 semitonos). Esto es lo que da a esta escala su simetría total y la ausencia de nota directriz." },
  { q: "¿Por qué la escala de tonos enteros no contiene nota directriz (sensible)?", opts: ["Por un error de construcción", "Porque todos los intervalos son idénticos (tonos enteros) — ningún semitono crea tensión direccional", "Porque es pentatónica", "Porque empieza en Do"], a: 1, fb: "La sensible funciona gracias al semitono que crea tensión hacia la tónica. En la escala de tonos enteros, todos los intervalos son tonos enteros — ningún semitono, por tanto ninguna tensión direccional, por tanto ninguna nota directriz. El flotamiento es total." },
  { q: "¿Qué tipo de acorde produce naturalmente la escala de tonos enteros?", opts: ["El acorde perfecto mayor (tercera M + quinta J)", "El acorde aumentado (tercera M + tercera M)", "El acorde disminuido (tercera m + tercera m)", "El acorde de dominante séptima"], a: 1, fb: "La escala de tonos enteros produce acordes aumentados: al apilar terceras sobre los grados de la escala de tonos enteros, se obtienen sistemáticamente terceras mayores superpuestas. Ej.: Do–Mi–Sol# = acorde aumentado." },
  { q: "¿Cuántas transposiciones distintas tiene la escala de tonos enteros?", opts: ["6 transposiciones distintas", "7 transposiciones distintas", "Solo 2 transposiciones distintas", "12 transposiciones distintas"], a: 2, fb: "La escala de tonos enteros solo puede transponerse de 2 maneras distintas antes de volver a sí misma. Ej.: Do–Re–Mi–Fa#–Sol#–La# y Reb–Mib–Fa–Sol–La–Si. Todas las demás 'transposiciones' reproducen una de estas dos escalas." },
  { q: "¿Qué famoso preludio de Debussy está enteramente construido sobre la escala de tonos enteros?", opts: ["Clair de Lune", "La Fille aux cheveux de lin", "Voiles", "La Cathédrale engloutie"], a: 2, fb: "'Voiles' (Preludios Libro I, 1909) es el ejemplo más conocido de pieza enteramente construida sobre la escala de tonos enteros. La sección central emplea la pentatónica, creando un sorprendente contraste de color." },
  { q: "La escala de tonos enteros Do–Re–Mi–Fa#–Sol#–La# produce qué acorde en Do:", opts: ["Do mayor (Do–Mi–Sol)", "Do aumentado (Do–Mi–Sol#)", "Do menor (Do–Mib–Sol)", "Do disminuido (Do–Mib–Solb)"], a: 1, fb: "Al construir un acorde en Do dentro de la escala de tonos enteros (Do–Re–Mi–Fa#–Sol#–La#), se toma Do, Mi (tercera M), Sol# (tercera M adicional) = Do aumentado. Todos los acordes de esta escala son aumentados." },
  { q: "¿Cuál es el color sonoro característico de la escala de tonos enteros?", opts: ["Tensión fuerte, desestabilizadora, resolución urgente", "Flotamiento, disolución tonal, misterio onírico", "Claridad diatónica, estructura sólida", "Violencia rítmica, color eslavo"], a: 1, fb: "La escala de tonos enteros crea un flotamiento tonal total — sin nota directriz, sin semitono, el oído no puede orientarse hacia ninguna tónica. El efecto es onírico, misterioso, disuelto — exactamente la estética impresionista de Debussy." },
  { q: "La escala de tonos enteros también se llama el modo __ de Messiaen.", opts: ["Modo 2", "Modo 3", "Modo 1", "Modo 4"], a: 2, fb: "Messiaen sistematizó las escalas simétricas en su tratado 'Técnica de mi lenguaje musical' (1944). La escala de tonos enteros es su modo 1 — el más simple, con solo 2 transposiciones posibles." },
  { q: "Entre la escala de tonos enteros en Do y la escala de tonos enteros en Reb, ¿cuántas notas son comunes?", opts: ["Ninguna nota común", "3 notas comunes", "Todas las notas — son las mismas", "Solo 1 nota común"], a: 0, fb: "Las dos escalas de tonos enteros distintas (Do–Re–Mi–Fa#–Sol#–La# y Reb–Mib–Fa–Sol–La–Si) no tienen ninguna nota en común (dejando aparte las enarmónicas). Juntas comparten los 12 semitonos." },
  { q: "¿Por qué se puede decir que la escala de tonos enteros es 'perfectamente simétrica'?", opts: ["Porque tiene 7 grados como la escala mayor", "Porque todos sus intervalos son idénticos — puede leerse desde cualquier grado y dar la misma escala", "Porque contiene un tritono en su centro", "Porque alterna tonos y semitonos"], a: 1, fb: "La simetría perfecta de la escala de tonos enteros proviene de la uniformidad de sus intervalos. Independientemente de la nota de partida dentro de la escala, la sucesión de intervalos es idéntica (T–T–T–T–T–T). Esta es una propiedad que no tiene la escala mayor." },
  { q: "En un contexto pedagógico, ¿cómo se distingue la escala de tonos enteros de la escala pentatónica?", opts: ["Son intercambiables — mismo efecto sonoro", "La escala de tonos enteros tiene 6 notas, flotamiento total, acordes aumentados; la pentatónica tiene 5 notas, serenidad, sin acorde de dominante", "La escala de tonos enteros es mayor, la pentatónica es menor", "La escala de tonos enteros viene de Asia, la pentatónica de Francia"], a: 1, fb: "Distinción esencial: escala de tonos enteros = 6 notas, solo tonos enteros, flotamiento tonal, acordes aumentados. Pentatónica = 5 notas, sin semitonos pero no siempre tonos enteros (T–T–T½–T–T½), serenidad, color oriental/folk." },

  // ── Tema 3: La escala octatónica — 12 preguntas ───────────────────────────
  { q: "¿Cuántas notas contiene la escala octatónica?", opts: ["6 notas", "7 notas", "8 notas", "9 notas"], a: 2, fb: "La escala octatónica ('octa' = 8) contiene 8 notas por octava. Ejemplo: Do–Re–Mib–Fa–Fa#–Sol#–La–Si–Do. Alterna tono y semitono (o semitono y tono según la versión)." },
  { q: "¿Cuál es el principio de construcción de la escala octatónica?", opts: ["Solo tonos enteros", "Alternancia tono–semitono (o semitono–tono)", "Solo semitonos", "Tercera menor + semitono en alternancia"], a: 1, fb: "La escala octatónica alterna estrictamente tono y semitono (T–½T–T–½T–T–½T–T–½T) o a la inversa (½T–T–½T–T–½T–T–½T–T). Esta simetría crea exactamente 8 notas por octava." },
  { q: "¿Qué acorde característico se encuentra naturalmente en la escala octatónica?", opts: ["El acorde aumentado", "El acorde de dominante séptima", "El acorde disminuido de séptima (dim7)", "El acorde de sexta napolitana"], a: 2, fb: "La escala octatónica contiene 3 acordes disminuidos de séptima (dim7): Do–Mib–Fa#–La, Re–Fa–Sol#–Si, y Mib–Fa#–La–Do. Es la escala ideal para construir secuencias de dim7." },
  { q: "¿Cuántas transposiciones distintas tiene la escala octatónica?", opts: ["2 transposiciones", "3 transposiciones", "4 transposiciones", "12 transposiciones"], a: 1, fb: "La escala octatónica solo tiene 3 transposiciones distintas. Después de 3 transposiciones de un semitono, se vuelve a la misma colección de notas. Es el modo 2 de Messiaen, con exactamente 3 transposiciones." },
  { q: "¿Qué compositor ruso usó masivamente la escala octatónica en sus ballets?", opts: ["Sergei Rachmaninov", "Pyotr Ilyich Tchaikovsky", "Igor Stravinsky", "Dmitri Shostakovich"], a: 2, fb: "Igor Stravinsky es el maestro de la escala octatónica, que emplea en sus grandes ballets (El pájaro de fuego, Petrushka, La consagración de la primavera). Le confiere ese característico color 'eslavo místico'." },
  { q: "¿Qué compositor francés teorizó la escala octatónica como 'modo 2 de transposiciones limitadas'?", opts: ["Claude Debussy", "Maurice Ravel", "Olivier Messiaen", "Gabriel Fauré"], a: 2, fb: "Olivier Messiaen sistematizó las escalas simétricas en 'Técnica de mi lenguaje musical' (1944). Llamó a la escala octatónica 'modo 2 de transposiciones limitadas' — 3 transposiciones posibles frente a 2 del modo 1." },
  { q: "La escala octatónica Do–Re–Mib–Fa–Fa#–Sol#–La–Si contiene cuántos acordes disminuidos séptima distintos:", opts: ["1 acorde dim7", "2 acordes dim7", "3 acordes dim7", "4 acordes dim7"], a: 2, fb: "Toda escala octatónica contiene exactamente 3 acordes dim7 entrelazados. En Do–Re–Mib–Fa–Fa#–Sol#–La–Si: (1) Do–Mib–Fa#–La, (2) Re–Fa–Sol#–Si, y (3) Mib–Fa#–La–Do. Estos tres acordes cubren los 12 sonidos cromáticos." },
  { q: "¿Cuál es el color sonoro característico de la escala octatónica?", opts: ["Flotamiento onírico sin tensión", "Tensión simétrica, misterio, inestabilidad organizada", "Serenidad, color oriental", "Claridad tonal diatónica"], a: 1, fb: "La escala octatónica crea una tensión simétrica particular — los acordes dim7 crean inestabilidad pero de forma ordenada. El color es oscuro, misterioso, tenso — característico del estilo eslavo místico de Stravinsky y la vistosidad de Messiaen." },
  { q: "La escala octatónica difiere de la escala de tonos enteros en que:", opts: ["La escala octatónica tiene 6 notas, la de tonos enteros tiene 8", "La escala octatónica alterna tono y semitono (8 notas), la de tonos enteros solo tiene tonos enteros (6 notas)", "Son idénticas — dos nombres para la misma escala", "La escala octatónica viene de Rusia, la de tonos enteros de Francia"], a: 1, fb: "Diferencia fundamental: escala de tonos enteros = 6 notas, todos tonos enteros, acordes aumentados. Escala octatónica = 8 notas, alternancia tono/semitono, acordes dim7. Dos colores muy distintos a pesar de su simetría común." },
  { q: "En 'Petrushka' de Stravinsky, el acorde 'bitonal' (Do mayor + Fa# mayor simultáneamente) es posible gracias a:", opts: ["La escala pentatónica", "La escala de tonos enteros", "La escala octatónica", "El sistema dodecafónico"], a: 2, fb: "El acorde 'Petrushka' (Do–Mi–Sol + Fa#–La#–Do#) se hace coherente gracias a la escala octatónica, que contiene ambos conjuntos de notas simultáneamente. La simetría octatónica permite esta característica bitonalidad." },
  { q: "¿Por qué el acorde disminuido de séptima (dim7) es particularmente ambiguo tonalmente?", opts: ["Porque contiene un tritono", "Porque está compuesto de terceras menores iguales — puede resolver hacia 4 tonalidades diferentes", "Porque es demasiado disonante para resolver", "Porque no pertenece a ninguna escala"], a: 1, fb: "El acorde dim7 está compuesto de 4 terceras menores superpuestas (Do–Mib–Fa#–La). Como todas sus terceras son iguales, es perfectamente simétrico y puede resolver hacia 4 tonalidades mayores o menores distintas — de ahí su extrema ambigüedad tonal." },
  { q: "La escala octatónica se llama 'modo 2' por Messiaen porque:", opts: ["Es la segunda escala que inventó", "Es la escala con 2 transposiciones distintas", "Es el segundo modo en su clasificación de los modos de transposiciones limitadas (después de la escala de tonos enteros)", "Es la escala que empieza en el 2º grado"], a: 2, fb: "Messiaen numeró sus modos según su complejidad y número de transposiciones. Modo 1 (2 transposiciones) = escala de tonos enteros. Modo 2 (3 transposiciones) = escala octatónica. La numeración sigue un orden lógico en su sistema." },

  // ── Tema 4: La escala pentatónica — 12 preguntas ─────────────────────────
  { q: "¿Cuántas notas contiene la escala pentatónica?", opts: ["4 notas", "5 notas", "6 notas", "7 notas"], a: 1, fb: "La escala pentatónica ('penta' = 5) contiene 5 notas. La versión más común en Do es: Do–Re–Mi–Sol–La. Se obtiene suprimiendo el Fa y el Si de la escala de Do mayor." },
  { q: "¿Qué caracteriza a la escala pentatónica en comparación con la escala mayor?", opts: ["Contiene más semitonos", "No contiene ningún semitono — lo que elimina cualquier tensión direccional", "Contiene un tritono central", "Siempre es menor"], a: 1, fb: "La escala pentatónica mayor Do–Re–Mi–Sol–La no contiene ningún semitono. La ausencia de semitono significa ausencia de sensible y de tritono — por tanto ninguna tensión direccional hacia una resolución. El sonido es sereno, abierto." },
  { q: "¿Qué nota está ausente de la pentatónica Do–Re–Mi–Sol–La en comparación con Do mayor?", opts: ["Re y Sol", "Fa y Si", "Mi y La", "Sol y Do"], a: 1, fb: "La escala de Do mayor es Do–Re–Mi–Fa–Sol–La–Si–Do. Al suprimir el Fa y el Si (las dos notas que forman el tritono y crean la tensión sensible-tónica), se obtiene la pentatónica Do–Re–Mi–Sol–La." },
  { q: "¿Por qué la escala pentatónica es universal — presente en casi todas las culturas musicales?", opts: ["Porque los antiguos griegos la impusieron al mundo", "Porque es fácil de tocar en cualquier instrumento", "Porque la ausencia de semitono la hace naturalmente consonante y universalmente accesible", "Porque los 5 dedos de la mano corresponden a las 5 notas"], a: 2, fb: "La ausencia de semitono en la escala pentatónica la hace naturalmente agradable al oído humano — ninguna nota crea tensión hacia una resolución. Esta propiedad de consonancia natural explica su presencia en las músicas de África, Asia, América y Europa." },
  { q: "La escala pentatónica se usa en la música impresionista para evocar:", opts: ["La complejidad de la armonía romántica alemana", "El color oriental, exótico o antiguo (gamelan, música china)", "El contrapunto barroco riguroso", "La danza folclórica irlandesa"], a: 1, fb: "Debussy descubrió el gamelan javanés en la Exposición Universal de 1889. Fascinado por el color pentatónico de esta música, lo integró en su lenguaje impresionista para evocar Oriente, el sueño y el exotismo." },
  { q: "¿Cuál es la relación entre la pentatónica y el jazz?", opts: ["El jazz evita sistemáticamente la pentatónica", "La pentatónica (especialmente menor) es una de las bases del jazz y el blues", "El jazz usa únicamente la pentatónica — nunca otras escalas", "La pentatónica es exclusiva de la música clásica"], a: 1, fb: "La escala pentatónica menor (Do–Mib–Fa–Sol–Sib) está en el corazón del blues y el jazz. Permite tocar 'de oído' sobre cualquier acorde sin disonancia — de ahí su omnipresencia en los solos de improvisación de jazz y blues." },
  { q: "La pentatónica menor sobre La es:", opts: ["La–Si–Do–Mi–Fa#", "La–Do–Re–Mi–Sol", "La–Sib–Do–Reb–Mib", "La–Si–Re–Mi–Sol#"], a: 1, fb: "La pentatónica menor sobre La es La–Do–Re–Mi–Sol. Estructura: T½–T–T–T½–T. Corresponde a la pentatónica mayor de Do (Do–Re–Mi–Sol–La) pero leída desde La — las dos comparten exactamente las mismas notas." },
  { q: "En 'Voiles' de Debussy, la sección central usa la pentatónica para crear:", opts: ["Un contraste de color con la escala de tonos enteros de la sección principal", "Una tensión máxima antes de la resolución final", "Un retorno a la tonalidad de Do mayor", "Un efecto de fuga barroca"], a: 0, fb: "'Voiles' está construida sobre la escala de tonos enteros (Do–Re–Mi–Fa#–Sol#–La#) en las secciones A. La sección central (B) usa la pentatónica (Sol#–La#–Do–Re–Mi) — este contraste de color es un golpe de genio: dos escalas sin semitonos, dos colores radicalmente diferentes." },
  { q: "La pentatónica se usa frecuentemente en la música folk y los cantos tradicionales porque:", opts: ["Es más fácil de memorizar con solo 5 notas", "Su ausencia de semitono permite una entonación más simple y adaptabilidad a distintas voces", "Los músicos tradicionales ignoraban las escalas de 7 notas", "Corresponde exactamente a los modos gregorianos"], a: 1, fb: "La ausencia de semitono en la pentatónica la hace especialmente adecuada para el canto tradicional: sin tensión de entonación en los semitonos, adaptable a distintos registros, naturalmente consonante entre varias voces." },
  { q: "¿Cuántas transposiciones distintas tiene la escala pentatónica?", opts: ["5 transposiciones distintas", "7 transposiciones distintas", "12 transposiciones distintas", "2 transposiciones distintas"], a: 2, fb: "La escala pentatónica tiene 12 transposiciones distintas — no es un 'modo de transposiciones limitadas'. A diferencia de la escala de tonos enteros (2) o la octatónica (3), la pentatónica puede transponerse 12 veces sin volver a sí misma antes de la octava." },
  { q: "¿Cuál es el acorde de dominante en la escala pentatónica Do–Re–Mi–Sol–La?", opts: ["Sol–Si–Re (V mayor)", "Sol–Sib–Re (V menor)", "No hay acorde de dominante en sentido funcional — Si y Fa están ausentes", "Sol–La–Re (acorde de quinta añadida)"], a: 2, fb: "La escala pentatónica no contiene Si (sensible) ni Fa. El acorde de dominante V7 (Sol–Si–Re–Fa) requiere precisamente estas dos notas. Sin sensible, no hay tensión funcional hacia I — es precisamente esto lo que da a la pentatónica su carácter sin resolución." },
  { q: "¿Qué diferencia fundamental existe entre la pentatónica y la escala de tonos enteros en cuanto al color?", opts: ["La pentatónica suena más 'moderna' que la escala de tonos enteros", "La escala de tonos enteros crea el flotamiento/misterio aumentado, la pentatónica crea la serenidad/claridad sin tensión", "La pentatónica es más disonante que la escala de tonos enteros", "No hay diferencia de color — ambas son 'impresionistas'"], a: 1, fb: "Escala de tonos enteros: flotamiento misterioso y disolución tonal (acordes aumentados, sin nota directriz). Pentatónica: serenidad y claridad sin tensión (consonancias naturales, color folk u oriental). Dos colores distintos pese a la ausencia común de semitono." },

  // ── Tema 5: Modos de Messiaen e intercambio modal — 12 preguntas ──────────
  { q: "¿Qué es un 'modo de transposiciones limitadas' según Messiaen?", opts: ["Un modo que no puede transponerse", "Un modo cuyas transposiciones sucesivas reproducen colecciones de notas idénticas antes de recorrer los 12 semitonos", "Un modo usado únicamente en la liturgia", "Un modo que se limita a 5 notas"], a: 1, fb: "Un modo de transposiciones limitadas es una escala cuya simetría interna hace que ciertas transposiciones reproduzcan exactamente la misma colección de notas. Ej.: la escala de tonos enteros en Do y en Re son dos escalas distintas, pero en Mi vuelve a Do — por tanto solo 2 transposiciones reales." },
  { q: "¿Cuántos modos de transposiciones limitadas catalogó Messiaen en su tratado de 1944?", opts: ["3 modos", "5 modos", "7 modos", "12 modos"], a: 2, fb: "Messiaen catalogó 7 modos de transposiciones limitadas en 'Técnica de mi lenguaje musical' (1944). Cada modo se caracteriza por su estructura de intervalos, su número de transposiciones y su 'color' particular." },
  { q: "El modo 1 de Messiaen tiene 2 transposiciones y el modo 2 tiene 3. ¿Qué significa este número creciente?", opts: ["Que el modo 2 es más complejo y más disonante", "Que cuantas más transposiciones, más débil es la simetría interna", "Cuantas más transposiciones distintas tiene un modo, más se acerca a una escala ordinaria — la simetría se debilita", "Que el modo 2 cubre más tonalidades que el modo 1"], a: 2, fb: "La lógica es la inversa de lo que se cree: menos transposiciones = mayor simetría interna (modo 1: 2 transposiciones, simetría máxima). Más transposiciones = simetría más débil. Una escala ordinaria tiene 12 transposiciones distintas — ninguna simetría interna particular." },
  { q: "¿Qué efecto busca Messiaen al usar los modos de transposiciones limitadas en sus obras?", opts: ["Maximizar la tensión armónica para una resolución dramática", "Crear un color único e inimitable gracias a la simetría interna del modo", "Recuperar el contrapunto barroco de Bach", "Hacer la música accesible al gran público"], a: 1, fb: "Messiaen buscaba explícitamente el 'color' armónico — cada modo de transposiciones limitadas posee un color único y reconocible. Su fe católica le llevó a asociar colores visuales precisos a cada modo (sinestesia)." },
  { q: "¿Qué es el 'intercambio modal' (préstamo modal)?", opts: ["Cambiar de modo dentro de una misma pieza — pasar de un modo a otro", "Tomar prestado un acorde de un modo paralelo o de la escala eólica (menor natural) permaneciendo en la misma tonalidad", "Transportar toda la pieza a otro modo", "Usar acordes de dos tonalidades diferentes simultáneamente (bitonalidad)"], a: 1, fb: "El intercambio modal consiste en tomar prestado puntualmente un acorde de otra escala basada en la misma tónica. En Do mayor, se puede tomar prestado IVm (Fa menor) del Do menor, bVI (Lab) o bVII (Sib) del Do eólico — sin salir de Do como centro tonal." },
  { q: "El acorde IVm prestado en Do mayor es:", opts: ["Fa–La–Do (Fa mayor)", "Fa–Lab–Do (Fa menor)", "Fa–La–Do# (Fa aumentado)", "Fa–Lab–Dob (Fa disminuido)"], a: 1, fb: "IVm en Do mayor = acorde menor sobre el 4º grado = Fa–Lab–Do. Este acorde se toma prestado del Do menor (o eólico) donde el La está bemolizado (Lab). Es uno de los préstamos modales más expresivos y frecuentes en música pop y jazz." },
  { q: "El acorde bVII en Do mayor (Sib–Re–Fa) se toma prestado del modo:", opts: ["Do dórico", "Do frigio", "Do mixolidio", "Do lidio"], a: 2, fb: "El modo mixolidio en Do (Do–Re–Mi–Fa–Sol–La–Sib) es idéntico a Do mayor pero con un Sib en lugar de Si. El acorde bVII (Sib mayor = Sib–Re–Fa) es natural en el modo mixolidio. Su efecto es característico del rock y la música modal." },
  { q: "¿Cuál es el efecto típico del acorde bVI (Lab en Do mayor) en una progresión en Do?", opts: ["Clarifica la tonalidad de Do", "Crea un color romántico y expresivo — un préstamo muy sorprendente", "Equivale a una dominante secundaria", "Siempre anuncia una modulación"], a: 1, fb: "El acorde bVI (Lab–Do–Mib) tomado prestado del Do menor/eólico crea un color romántico repentino y muy expresivo. Su color 'inesperado' en un contexto mayor es muy llamativo — frecuente en Schubert y en la música pop (ej. el 'flat-six chord' de las baladas rock)." },
  { q: "La progresión I–bVI–bVII–I en Do mayor usa préstamos de los modos:", opts: ["Dórico y frigio únicamente", "Eólico (para bVI y bVII) y mixolidio (para bVII)", "Lidio y locrio", "Sin préstamos modales — son acordes diatónicos de Do mayor"], a: 1, fb: "En Do mayor: bVI = Lab (prestado del Do eólico que tiene Lab), bVII = Sib (prestado del Do mixolidio que tiene Sib). Esta progresión (Do–Lab–Sib–Do) es muy frecuente en el rock y el pop — combina dos sabores modales distintos." },
  { q: "¿Por qué el intercambio modal no crea una modulación?", opts: ["Porque solo usa acordes mayores", "Porque la tónica permanece igual — el préstamo es puntual, no estructural", "Porque no usa ningún acorde de dominante", "Porque siempre dura menos de un compás"], a: 1, fb: "El intercambio modal es un préstamo puntual — la tónica no cambia. En Do mayor, tomar prestado Lab (bVI) crea un color, pero Do sigue siendo el centro tonal. Una modulación implica un cambio de centro tonal confirmado por una cadencia en la nueva tonalidad." },
  { q: "El modo 3 de Messiaen tiene 4 transposiciones y 9 notas. Su estructura es:", opts: ["T–T–T–T–T–T–T–T (8 tonos enteros)", "T–½T–½T repetido 3 veces (grupos de 3 notas)", "½T–T–½T–T repetido 4 veces", "T–½T–T–T–½T–T–T–½T–T"], a: 1, fb: "El modo 3 de Messiaen está construido sobre grupos de 3 notas: T–½T–½T, repetido 3 veces para cubrir la octava. Su estructura es Do–Re–Mib–Mi–Fa#–Sol–Sol#–La#–Si. Tiene 4 transposiciones distintas y un color más cromático y denso que los modos 1 y 2." },
  { q: "¿Cuál es la propiedad común a todos los modos de transposiciones limitadas de Messiaen?", opts: ["Todos contienen exactamente 6 notas", "Todos tienen una simetría interna que hace que ciertas transposiciones produzcan la misma colección de notas", "Todos se derivan de la escala mayor suprimiendo notas", "Todos están construidos sobre tritonos"], a: 1, fb: "La propiedad fundamental común a todos los modos de transposiciones limitadas es su simetría interna. Esta simetría hace que, después de un cierto número de transposiciones (menos de 12), se vuelva exactamente a la misma colección de alturas. Es el criterio que los distingue de las escalas 'ordinarias'." },
];

const questionsDe: Question[] = [
  // ── Thema 1: Planing (Parallelführung) — 12 Fragen ───────────────────────
  { q: "Was ist Planing in der impressionistischen Harmonik?", opts: ["Eine Technik zur Auflösung von Dissonanzen", "Das Gleiten eines vollständigen Akkords in Parallelbewegung ohne funktionale Auflösung", "Eine Ganztonleiter", "Eine charakteristische V–I-Progression"], a: 1, fb: "Planing ist das Gleiten eines vollständigen Akkords (mit allen seinen Stimmen) in Parallelbewegung. Die Klangfarbe des Akkords verschiebt sich, ohne dass die Spannungen sich auflösen — der Effekt ist ein 'Klangblock, der gleitet'." },
  { q: "Was ist der Unterschied zwischen diatonischem und chromatischem Planing?", opts: ["Diatonisches Planing verwendet Halbtöne, chromatisches Ganztöne", "Diatonisches Planing bewahrt denselben Akkordtyp auf jedem Skalenstufe, chromatisches Planing transponiert exakt denselben Akkord", "Diatonisches Planing ist Ravels Technik, chromatisches die von Debussy", "Es gibt keinen Unterschied — beide Begriffe bezeichnen dieselbe Technik"], a: 1, fb: "Diatonisches Planing: Akkorde wechseln die Qualität gemäß den Skalenstufen (z. B. Sextakkorde in parallelen Terzen). Chromatisches Planing: exakt derselbe Akkord (gleiche Qualität) gleitet chromatisch — alle Stimmen bewegen sich um dasselbe Intervall." },
  { q: "Was geschieht beim chromatischen Planing mit den Akkorden, wenn sie sich bewegen?", opts: ["Sie wechseln die Qualität (Dur → Moll gemäß dem Grad)", "Sie behalten genau dieselbe Intervallstruktur — nur die Tonhöhe ändert sich", "Sie verlieren ihre Quinten, um Parallelen zu vermeiden", "Sie lösen sich bei jeder Verschiebung zur Tonika auf"], a: 1, fb: "Beim chromatischen Planing wird der Akkord exakt transponiert: Wenn es ein Dominantseptakkord ist, bleibt er bei jedem Schritt ein Dominantseptakkord. Die Qualität wird beibehalten, nur die Tonhöhe variiert." },
  { q: "Warum werden Quinten- und Oktavenparallelen beim Planing toleriert?", opts: ["Weil sie beim Planing selten sind", "Weil das Planing genau auf diesem Parallelklangblock-Effekt beruht — es ist absichtlich, kein Fehler", "Weil Debussy die Kontrapunktregeln nicht kannte", "Weil sie durch aufgelöste Dissonanzen kompensiert werden"], a: 1, fb: "Planing widerspricht den Regeln des klassischen Kontrapunkts absichtlich. Quintenparallelen erzeugen den charakteristischen 'Block'-Effekt — der Klang gleitet wie ein einziges Objekt. Es ist eine ästhetische Entscheidung, keine Nachlässigkeit." },
  { q: "Welcher Komponist ist der unangefochtene Meister des impressionistischen Planings?", opts: ["César Franck", "Claude Debussy", "Johannes Brahms", "Ludwig van Beethoven"], a: 1, fb: "Claude Debussy ist der Schöpfer und Meister des impressionistischen Planings. Sein Stück 'La Cathédrale engloutie' und seine Préludes sind voller Akkorde in Parallelbewegung, die Farbeffekte ohne funktionale Auflösung erzeugen." },
  { q: "Wie analysiert man Planing — mit den Funktionen T/SD/D oder anders?", opts: ["Mit den klassischen T/SD/D-Funktionen, wie jeden tonalen Akkord", "Nach Farbe und Register: den Ausgangsakkord identifizieren, die Bewegung notieren, den Klangeffekt beschreiben", "Nur durch Schenkerian-Analyse", "Planing kann nicht analysiert werden — es ist Improvisation"], a: 1, fb: "Funktionale Analyse (T/SD/D) gilt nicht für Planing: Es gibt keine Spannung-Auflösung im klassischen Sinn. Die Analyse erfolgt nach Farbe (Akkordtyp), Register (tief/hoch) und Effekt (Schweben, Opazität, Klarheit)." },
  { q: "Beim diatonischen Planing, wenn wir auf I (Durakkord) beginnen, wird der Akkord auf II:", opts: ["Stets ein Durakkord", "Moll, weil II in der Durtonleiter moll ist", "Vermindert, weil II vermindert ist", "Übermäßig, weil die Tonleiter es erfordert"], a: 1, fb: "Beim diatonischen Planing folgen die Akkorde der diatonischen Qualität jeder Stufe. In C-Dur ist II D-Moll (D–F–A). Diatonisches Planing bewahrt die Tonart — Akkorde wechseln die Qualität gemäß der Stufe." },
  { q: "Debussys Stück 'La Cathédrale engloutie' verwendet massiv:", opts: ["Klassische Sekundärdominanten", "Übereinander gestapelte Quartenakkorde", "Akkorde in parallelem Planing zur Evokation von Glocken unter Wasser", "Zwölftonleitern"], a: 2, fb: "'La Cathédrale engloutie' verwendet Akkordblöcke (häufig Quinten und Quarten) in Parallelbewegung, um Glockenresonanzen zu simulieren. Das Planing erzeugt den charakteristischen Unterwasser-Immersionseffekt des Stücks." },
  { q: "Planing erschien hauptsächlich in welcher Musikrichtung?", opts: ["Barockpolyphonie", "Deutsche Romantikharmonik (Brahms, Wagner)", "Französischer Impressionismus (Debussy, Ravel)", "Wiener Dodekaphonismus (Schoenberg)"], a: 2, fb: "Planing ist eine charakteristische Technik des französischen Impressionismus, entwickelt von Debussy und Ravel Ende des 19. und Anfang des 20. Jahrhunderts. Es bezieht seine Inspiration aus japanischer Musik (Gamelan) und orientalischen Holzschnitten." },
  { q: "Was ersetzt beim Planing die klassische Harmonikfunktion?", opts: ["Strenger 4-stimmiger Kontrapunkt", "Die Klangfarbe, das Register und die Klangfarbe des Akkords", "Die Progression durch Tritoni", "Die strenge Abwechslung Moll/Dur"], a: 1, fb: "In der impressionistischen Harmonik ersetzen Farbe (Akkordqualität: Dur, Sept, None), Register (tief, mittel, hoch) und Timbre (offene oder geschlossene Lage) die Spannung-Auflösungslogik des tonalen Systems." },
  { q: "Ein Maj7-Akkord beim chromatischen Planing, der um einen Halbton steigt, wird:", opts: ["Ein Mollakkord", "Derselbe Typ Maj7-Akkord, aber einen Halbton höher", "Ein verminderter Akkord", "Ein Dominantseptakkord"], a: 1, fb: "Beim chromatischen Planing wird die Akkordstruktur beibehalten. C Maj7 (C–E–G–H) um einen Halbton höher transponiert ergibt Des Maj7 (Des–F–As–C). Gleiche Intervallstruktur, andere Tonhöhe." },
  { q: "Was ist die typische Hörerfahrung beim Planing?", opts: ["Wachsende Spannung in Richtung einer starken Auflösung", "Ein farbiges Gleiten ohne funktionale Richtung — wie ein klingendes Aquarell", "Eine Verstärkung der Haupttonart", "Eine Auflösung in die Stille"], a: 1, fb: "Planing erzeugt ein Gefühl des Gleitens oder Schwebens — der Akkord bewegt sich wie ein einzelnes Objekt im Klangraum. Es gibt keine funktionale Richtung zu einer Auflösung, nur eine Farbverschiebung." },

  // ── Thema 2: Die Ganztonleiter — 12 Fragen ────────────────────────────────
  { q: "Wie viele Töne enthält die Ganztonleiter?", opts: ["5 Töne", "6 Töne", "7 Töne", "8 Töne"], a: 1, fb: "Die Ganztonleiter enthält 6 Töne, alle durch einen Ganzton (2 Halbtöne) getrennt. Beispiel: C–D–E–Fis–Gis–Ais (dann zurück zu C). Es gibt nur 2 verschiedene Ganztonleitern (alle anderen sind Transpositionen, die mit einer der beiden identisch sind)." },
  { q: "Welches Intervall liegt zwischen jedem Ton der Ganztonleiter?", opts: ["Ein Halbton (½T)", "Ein Ganzton (T)", "Eine kleine Terz (T½)", "Ein Tritonus"], a: 1, fb: "Jede Stufe der Ganztonleiter ist von der nächsten durch einen Ganzton (2 Halbtöne) getrennt. Das gibt dieser Leiter ihre totale Symmetrie und das Fehlen eines Leittons." },
  { q: "Warum enthält die Ganztonleiter keinen Leitton?", opts: ["Durch einen Konstruktionsfehler", "Weil alle Intervalle identisch sind (Ganztöne) — kein Halbton erzeugt gerichtete Spannung", "Weil sie pentatonisch ist", "Weil sie auf C beginnt"], a: 1, fb: "Der Leitton funktioniert durch den Halbton, der Spannung zur Tonika erzeugt. In der Ganztonleiter sind alle Intervalle Ganztöne — kein Halbton, also keine gerichtete Spannung, also kein Leitton. Das Schweben ist total." },
  { q: "Welcher Akkordtyp wird von der Ganztonleiter natürlich erzeugt?", opts: ["Durakkord (große Terz + reine Quinte)", "Übermäßiger Akkord (große Terz + große Terz)", "Verminderter Akkord (kleine Terz + kleine Terz)", "Dominantseptakkord"], a: 1, fb: "Die Ganztonleiter erzeugt übermäßige Akkorde: Beim Aufschichten von Terzen auf den Stufen der Ganztonleiter erhält man systematisch übereinanderliegende große Terzen. Bsp.: C–E–Gis = übermäßiger Akkord." },
  { q: "Wie viele verschiedene Transpositionen hat die Ganztonleiter?", opts: ["6 verschiedene Transpositionen", "7 verschiedene Transpositionen", "Nur 2 verschiedene Transpositionen", "12 verschiedene Transpositionen"], a: 2, fb: "Die Ganztonleiter kann nur auf 2 verschiedene Arten transponiert werden, bevor sie zu sich selbst zurückkehrt. Bsp.: C–D–E–Fis–Gis–Ais und Des–Es–F–G–A–H. Alle anderen 'Transpositionen' ergeben eine der beiden Leitern." },
  { q: "Welches berühmte Prélude von Debussy ist vollständig auf der Ganztonleiter aufgebaut?", opts: ["Clair de Lune", "La Fille aux cheveux de lin", "Voiles", "La Cathédrale engloutie"], a: 2, fb: "'Voiles' (Préludes Buch I, 1909) ist das bekannteste Beispiel eines vollständig auf der Ganztonleiter aufgebauten Stücks. Der mittlere Abschnitt verwendet die Pentatonik und erzeugt einen frappierenden Farbkontrast." },
  { q: "Die Ganztonleiter C–D–E–Fis–Gis–Ais erzeugt welchen Akkord auf C?", opts: ["C-Dur (C–E–G)", "C übermäßig (C–E–Gis)", "C-Moll (C–Es–G)", "C vermindert (C–Es–Ges)"], a: 1, fb: "Beim Aufbau eines Akkords auf C in der Ganztonleiter (C–D–E–Fis–Gis–Ais) nimmt man C, E (große Terz), Gis (weitere große Terz) = C übermäßig. Alle Akkorde dieser Leiter sind übermäßig." },
  { q: "Was ist die charakteristische Klangfarbe der Ganztonleiter?", opts: ["Starke Spannung, destabilisierend, dringende Auflösung", "Schweben, tonale Auflösung, traumhaftes Mysterium", "Diatonische Klarheit, solide Struktur", "Rhythmische Gewalt, slawische Farbe"], a: 1, fb: "Die Ganztonleiter erzeugt totales tonales Schweben — ohne Leitton, ohne Halbton kann sich das Ohr auf keine Tonika ausrichten. Der Effekt ist traumhaft, geheimnisvoll, aufgelöst — genau die impressionistische Ästhetik Debussys." },
  { q: "Die Ganztonleiter wird auch Messiaens Modus __ genannt.", opts: ["Modus 2", "Modus 3", "Modus 1", "Modus 4"], a: 2, fb: "Messiaen systematisierte symmetrische Leitern in seinem Traktat 'Technik meiner musikalischen Sprache' (1944). Die Ganztonleiter ist sein Modus 1 — der einfachste, mit nur 2 möglichen Transpositionen." },
  { q: "Zwischen der Ganztonleiter auf C und der Ganztonleiter auf Des, wie viele Töne sind gemeinsam?", opts: ["Keine gemeinsamen Töne", "3 gemeinsame Töne", "Alle Töne — sie sind identisch", "Nur 1 gemeinsamer Ton"], a: 0, fb: "Die beiden verschiedenen Ganztonleitern (C–D–E–Fis–Gis–Ais und Des–Es–F–G–A–H) haben keinen einzigen gemeinsamen Ton (abgesehen von enharmonischen Entsprechungen). Zusammen teilen sie alle 12 Halbtöne." },
  { q: "Warum kann man sagen, dass die Ganztonleiter 'vollkommen symmetrisch' ist?", opts: ["Weil sie 7 Stufen hat wie die Durtonleiter", "Weil alle ihre Intervalle identisch sind — sie kann von jeder Stufe gelesen werden und ergibt dieselbe Leiter", "Weil sie einen Tritonus in ihrer Mitte enthält", "Weil sie Töne und Halbtöne abwechselt"], a: 1, fb: "Die vollkommene Symmetrie der Ganztonleiter stammt aus der Gleichförmigkeit ihrer Intervalle. Unabhängig vom Startton innerhalb der Leiter ist die Intervallfolge identisch (T–T–T–T–T–T). Das ist eine Eigenschaft, die die Durtonleiter nicht besitzt." },
  { q: "In einem pädagogischen Kontext, wie unterscheidet sich die Ganztonleiter von der Pentatonik?", opts: ["Sie sind austauschbar — gleicher Klangeffekt", "Die Ganztonleiter hat 6 Töne, totales Schweben, übermäßige Akkorde; die Pentatonik hat 5 Töne, Gelassenheit, keinen Dominantakkord", "Die Ganztonleiter ist Dur, die Pentatonik Moll", "Die Ganztonleiter kommt aus Asien, die Pentatonik aus Frankreich"], a: 1, fb: "Wesentlicher Unterschied: Ganztonleiter = 6 Töne, nur Ganztöne, tonales Schweben, übermäßige Akkorde. Pentatonik = 5 Töne, keine Halbtöne aber nicht immer Ganztöne (T–T–T½–T–T½), Gelassenheit, orientalische/Folk-Farbe." },

  // ── Thema 3: Die oktatonische Leiter — 12 Fragen ─────────────────────────
  { q: "Wie viele Töne enthält die oktatonische Leiter?", opts: ["6 Töne", "7 Töne", "8 Töne", "9 Töne"], a: 2, fb: "Die oktatonische Leiter ('octa' = 8) enthält 8 Töne pro Oktave. Beispiel: C–D–Es–F–Fis–Gis–A–H–C. Sie wechselt Ganzton und Halbton ab (oder Halbton und Ganzton je nach Version)." },
  { q: "Was ist das Konstruktionsprinzip der oktatonischen Leiter?", opts: ["Nur Ganztöne", "Abwechslung Ganzton–Halbton (oder Halbton–Ganzton)", "Nur Halbtöne", "Kleine Terz + Halbton abwechselnd"], a: 1, fb: "Die oktatonische Leiter wechselt streng Ganzton und Halbton ab (T–½T–T–½T–T–½T–T–½T) oder umgekehrt (½T–T–½T–T–½T–T–½T–T). Diese Symmetrie erzeugt genau 8 Töne innerhalb der Oktave." },
  { q: "Welcher charakteristische Akkord ist natürlich in der oktatonischen Leiter enthalten?", opts: ["Der übermäßige Akkord", "Der Dominantseptakkord", "Der verminderte Septakkord (dim7)", "Der neapolitanische Sextakkord"], a: 2, fb: "Die oktatonische Leiter enthält 3 verminderte Septakkorde (dim7): C–Es–Fis–A, D–F–Gis–H und Es–Fis–A–C. Sie ist die ideale Leiter für den Aufbau von dim7-Sequenzen." },
  { q: "Wie viele verschiedene Transpositionen hat die oktatonische Leiter?", opts: ["2 Transpositionen", "3 Transpositionen", "4 Transpositionen", "12 Transpositionen"], a: 1, fb: "Die oktatonische Leiter hat nur 3 verschiedene Transpositionen. Nach 3 Transpositionen um einen Halbton kehrt man zur gleichen Notensammlung zurück. Es ist Messiaens Modus 2, mit genau 3 Transpositionen." },
  { q: "Welcher russische Komponist verwendete die oktatonische Leiter massiv in seinen Balletten?", opts: ["Sergei Rachmaninow", "Pjotr Iljitsch Tschaikowski", "Igor Strawinsky", "Dmitri Schostakowitsch"], a: 2, fb: "Igor Strawinsky ist der Meister der oktatonischen Leiter, die er in seinen großen Balletten verwendet (Der Feuervogel, Petruschka, Le Sacre du Printemps). Sie verleiht ihm diese charakteristische 'slawisch-mystische' Farbe." },
  { q: "Welcher französische Komponist theoretisierte die oktatonische Leiter als 'Modus 2 mit begrenzten Transpositionen'?", opts: ["Claude Debussy", "Maurice Ravel", "Olivier Messiaen", "Gabriel Fauré"], a: 2, fb: "Olivier Messiaen systematisierte symmetrische Leitern in 'Technik meiner musikalischen Sprache' (1944). Er nannte die oktatonische Leiter 'Modus 2 mit begrenzten Transpositionen' — 3 mögliche Transpositionen gegenüber 2 bei Modus 1." },
  { q: "Die oktatonische Leiter C–D–Es–F–Fis–Gis–A–H enthält wie viele verschiedene verminderte Septakkorde?", opts: ["1 dim7-Akkord", "2 dim7-Akkorde", "3 dim7-Akkorde", "4 dim7-Akkorde"], a: 2, fb: "Jede oktatonische Leiter enthält genau 3 ineinandergreifende dim7-Akkorde. In C–D–Es–F–Fis–Gis–A–H: (1) C–Es–Fis–A, (2) D–F–Gis–H und (3) Es–Fis–A–C. Diese drei Akkorde decken alle 12 chromatischen Töne ab." },
  { q: "Was ist die charakteristische Klangfarbe der oktatonischen Leiter?", opts: ["Traumhaftes Schweben ohne Spannung", "Symmetrische Spannung, Mysterium, organisierte Instabilität", "Gelassenheit, orientalische Farbe", "Diatonische tonale Klarheit"], a: 1, fb: "Die oktatonische Leiter erzeugt eine besondere symmetrische Spannung — dim7-Akkorde erzeugen Instabilität, aber in geordneter Weise. Die Farbe ist dunkel, geheimnisvoll, gespannt — charakteristisch für Strawinskys slawisch-mystischen Stil und Messiaens Pracht." },
  { q: "Die oktatonische Leiter unterscheidet sich von der Ganztonleiter dadurch, dass:", opts: ["Die oktatonische Leiter 6 Töne hat, die Ganztonleiter 8", "Die oktatonische Leiter Ganzton und Halbton wechselt (8 Töne), die Ganztonleiter nur Ganztöne hat (6 Töne)", "Sie identisch sind — zwei Namen für dieselbe Leiter", "Die oktatonische Leiter aus Russland kommt, die Ganztonleiter aus Frankreich"], a: 1, fb: "Grundlegender Unterschied: Ganztonleiter = 6 Töne, nur Ganztöne, übermäßige Akkorde. Oktatonische Leiter = 8 Töne, Wechsel Ganzton/Halbton, dim7-Akkorde. Zwei sehr verschiedene Farben trotz ihrer gemeinsamen Symmetrie." },
  { q: "In Strawinskys 'Petruschka' ist der 'bitonale' Akkord (C-Dur + Fis-Dur gleichzeitig) möglich dank:", opts: ["Der Pentatonik", "Der Ganztonleiter", "Der oktatonischen Leiter", "Dem Zwölftonsystem"], a: 2, fb: "Der 'Petruschka-Akkord' (C–E–G + Fis–Ais–Cis) wird durch die oktatonische Leiter kohärent, die beide Notengruppen gleichzeitig enthält. Die oktatonische Symmetrie ermöglicht diese charakteristische Bitonalität." },
  { q: "Warum ist der verminderte Septakkord (dim7) tonal besonders mehrdeutig?", opts: ["Weil er einen Tritonus enthält", "Weil er aus gleichen kleinen Terzen besteht — er kann in 4 verschiedene Tonarten auflösen", "Weil er zu dissonant ist, um sich aufzulösen", "Weil er zu keiner Leiter gehört"], a: 1, fb: "Der dim7-Akkord besteht aus 4 übereinandergestapelten kleinen Terzen (C–Es–Fis–A). Da alle seine Terzen gleich sind, ist er vollkommen symmetrisch und kann in 4 verschiedene Dur- oder Molltonarten auflösen — daher seine extreme tonale Mehrdeutigkeit." },
  { q: "Die oktatonische Leiter wird von Messiaen 'Modus 2' genannt, weil:", opts: ["Es die zweite Leiter ist, die er erfunden hat", "Es die Leiter mit 2 verschiedenen Transpositionen ist", "Es der zweite Modus in seiner Klassifikation der Modi mit begrenzten Transpositionen ist (nach der Ganztonleiter)", "Es die Leiter ist, die auf der 2. Stufe beginnt"], a: 2, fb: "Messiaen nummerierte seine Modi nach ihrer Komplexität und der Anzahl ihrer Transpositionen. Modus 1 (2 Transpositionen) = Ganztonleiter. Modus 2 (3 Transpositionen) = oktatonische Leiter. Die Nummerierung folgt einer logischen Reihenfolge in seinem System." },

  // ── Thema 4: Die Pentatonik — 12 Fragen ─────────────────────────────────
  { q: "Wie viele Töne enthält die Pentatonik?", opts: ["4 Töne", "5 Töne", "6 Töne", "7 Töne"], a: 1, fb: "Die Pentatonik ('penta' = 5) enthält 5 Töne. Die häufigste Version auf C ist: C–D–E–G–A. Sie wird durch Weglassen von F und H aus der C-Durtonleiter gewonnen." },
  { q: "Was charakterisiert die Pentatonik im Vergleich zur Durtonleiter?", opts: ["Sie enthält mehr Halbtöne", "Sie enthält keinen Halbton — was jede gerichtete Spannung beseitigt", "Sie enthält einen zentralen Tritonus", "Sie ist stets moll"], a: 1, fb: "Die Dur-Pentatonik C–D–E–G–A enthält keinen Halbton. Das Fehlen des Halbtons bedeutet das Fehlen von Leitton und Tritonus — also keine gerichtete Spannung zu einer Auflösung. Der Klang ist heiter, offen." },
  { q: "Welcher Ton fehlt in der Pentatonik C–D–E–G–A im Vergleich zu C-Dur?", opts: ["D und G", "F und H", "E und A", "G und C"], a: 1, fb: "Die C-Durtonleiter ist C–D–E–F–G–A–H–C. Durch Weglassen von F und H (die beiden Töne, die den Tritonus bilden und die Leitton-Tonika-Spannung erzeugen) erhält man die Pentatonik C–D–E–G–A." },
  { q: "Warum ist die Pentatonik universal — in fast allen Musikkulturen vorhanden?", opts: ["Weil die alten Griechen sie der Welt aufzwangen", "Weil sie auf jedem Instrument leicht zu spielen ist", "Weil das Fehlen von Halbtönen sie natürlich konsonant und universell zugänglich macht", "Weil die 5 Finger der Hand den 5 Tönen entsprechen"], a: 2, fb: "Das Fehlen von Halbtönen in der Pentatonik macht sie dem menschlichen Ohr natürlich angenehm — kein Ton erzeugt Spannung zu einer Auflösung. Diese Eigenschaft natürlicher Konsonanz erklärt ihre Präsenz in den Musiken Afrikas, Asiens, Amerikas und Europas." },
  { q: "Die Pentatonik wird in der impressionistischen Musik verwendet, um zu evozieren:", opts: ["Die Komplexität der deutschen Romantikharmonik", "Orientalische, exotische oder archaische Farbe (Gamelan, chinesische Musik)", "Strengen Barockpolyphonie", "Irischen Volkstanz"], a: 1, fb: "Debussy entdeckte das javanische Gamelan auf der Weltausstellung von 1889. Fasziniert von der pentatonischen Farbe dieser Musik, integrierte er sie in seine impressionistische Sprache, um den Orient, den Traum und das Exotische zu evozieren." },
  { q: "Was ist die Beziehung zwischen der Pentatonik und dem Jazz?", opts: ["Jazz vermeidet die Pentatonik systematisch", "Die Pentatonik (besonders moll) ist eine der Grundlagen des Jazz und Blues", "Jazz verwendet nur die Pentatonik — nie andere Leitern", "Die Pentatonik ist ausschließlich der klassischen Musik vorbehalten"], a: 1, fb: "Die Moll-Pentatonik (C–Es–F–G–B) steht im Herzen von Blues und Jazz. Sie ermöglicht das Spielen 'nach Gehör' auf jedem Akkord ohne Dissonanz — daher ihre Allgegenwart in Jazz- und Blues-Improvisationssolos." },
  { q: "Die Moll-Pentatonik auf A ist:", opts: ["A–H–C–E–Fis", "A–C–D–E–G", "A–B–C–Des–Es", "A–H–D–E–Gis"], a: 1, fb: "Die Moll-Pentatonik auf A ist A–C–D–E–G. Struktur: T½–T–T–T½–T. Sie entspricht der C-Dur-Pentatonik (C–D–E–G–A), aber von A aus gelesen — beide teilen genau dieselben Töne." },
  { q: "In Debussys 'Voiles' verwendet der mittlere Abschnitt die Pentatonik, um zu erzeugen:", opts: ["Einen Farbkontrast mit der Ganztonleiter des Hauptabschnitts", "Maximale Spannung vor der abschließenden Auflösung", "Eine Rückkehr zur C-Dur-Tonalität", "Einen Barockfugen-Effekt"], a: 0, fb: "'Voiles' ist in den A-Abschnitten auf der Ganztonleiter (C–D–E–Fis–Gis–Ais) aufgebaut. Der mittlere Abschnitt (B) verwendet die Pentatonik (Gis–Ais–C–D–E) — dieser Farbkontrast ist ein Geniestreich: zwei Leitern ohne Halbtöne, zwei radikal verschiedene Farben." },
  { q: "Die Pentatonik wird häufig in der Folk-Musik und den traditionellen Gesängen verwendet, weil:", opts: ["Sie mit nur 5 Tönen leichter zu memorieren ist", "Das Fehlen von Halbtönen einfachere Intonation und Anpassungsfähigkeit an verschiedene Stimmen ermöglicht", "Traditionelle Musiker 7-töncige Leitern nicht kannten", "Sie genau den gregorianischen Modi entspricht"], a: 1, fb: "Das Fehlen von Halbtönen in der Pentatonik macht sie besonders für den traditionellen Gesang geeignet: keine Intonationsspannung auf Halbtönen, anpassbar an verschiedene Register, natürlich konsonant zwischen mehreren Stimmen." },
  { q: "Wie viele verschiedene Transpositionen hat die Pentatonik?", opts: ["5 verschiedene Transpositionen", "7 verschiedene Transpositionen", "12 verschiedene Transpositionen", "2 verschiedene Transpositionen"], a: 2, fb: "Die Pentatonik hat 12 verschiedene Transpositionen — sie ist kein 'Modus mit begrenzten Transpositionen'. Im Gegensatz zur Ganztonleiter (2) oder der oktatonischen Leiter (3) kann die Pentatonik 12 Mal transponiert werden, ohne vor der Oktave zu sich selbst zurückzukehren." },
  { q: "Was ist der Dominantakkord in der Pentatonik C–D–E–G–A?", opts: ["G–H–D (V Dur)", "G–B–D (V Moll)", "Es gibt keinen Dominantakkord im funktionalen Sinn — H und F fehlen", "G–A–D (Quintzusatzakkord)"], a: 2, fb: "Die Pentatonik enthält kein H (Leitton) und kein F. Der Dominantseptakkord V7 (G–H–D–F) erfordert jedoch genau diese beiden Töne. Ohne Leitton keine funktionale Spannung zu I — genau das gibt der Pentatonik ihren auflösungslosen Charakter." },
  { q: "Welcher grundlegende Farbunterschied besteht zwischen der Pentatonik und der Ganztonleiter?", opts: ["Die Pentatonik klingt 'moderner' als die Ganztonleiter", "Die Ganztonleiter erzeugt Schweben/übermäßiges Mysterium, die Pentatonik Gelassenheit/Klarheit ohne Spannung", "Die Pentatonik ist dissonanter als die Ganztonleiter", "Es gibt keinen Farbunterschied — beide sind 'impressionistisch'"], a: 1, fb: "Ganztonleiter: geheimnisvolles Schweben und tonale Auflösung (übermäßige Akkorde, kein Leitton). Pentatonik: Gelassenheit und Klarheit ohne Spannung (natürliche Konsonanzen, Folk- oder orientalische Farbe). Zwei verschiedene Farben trotz des gemeinsamen Fehlens von Halbtönen." },

  // ── Thema 5: Messiaens Modi und modaler Austausch — 12 Fragen ───────────
  { q: "Was ist laut Messiaen ein 'Modus mit begrenzten Transpositionen'?", opts: ["Ein Modus, der nicht transponiert werden kann", "Ein Modus, dessen aufeinanderfolgende Transpositionen identische Notensammlungen reproduzieren, bevor alle 12 Halbtöne durchlaufen sind", "Ein Modus, der nur in der Liturgie verwendet wird", "Ein Modus, der auf 5 Töne begrenzt ist"], a: 1, fb: "Ein Modus mit begrenzten Transpositionen ist eine Leiter, deren innere Symmetrie bewirkt, dass bestimmte Transpositionen genau dieselbe Notensammlung reproduzieren. Bsp.: Die Ganztonleiter auf C und auf D sind zwei verschiedene Leitern, auf E kehrt sie jedoch zu C zurück — also nur 2 wirkliche Transpositionen." },
  { q: "Wie viele Modi mit begrenzten Transpositionen hat Messiaen in seinem Traktat von 1944 katalogisiert?", opts: ["3 Modi", "5 Modi", "7 Modi", "12 Modi"], a: 2, fb: "Messiaen katalogisierte 7 Modi mit begrenzten Transpositionen in 'Technik meiner musikalischen Sprache' (1944). Jeder Modus wird durch seine Intervallstruktur, seine Anzahl von Transpositionen und seine besondere 'Farbe' charakterisiert." },
  { q: "Messiaens Modus 1 hat 2 Transpositionen und Modus 2 hat 3. Was bedeutet diese steigende Zahl?", opts: ["Dass Modus 2 komplexer und dissonanter ist", "Dass mehr Transpositionen, desto schwächer die innere Symmetrie", "Je mehr verschiedene Transpositionen ein Modus hat, desto näher kommt er einer gewöhnlichen Leiter — die Symmetrie schwächt sich ab", "Dass Modus 2 mehr Tonarten abdeckt als Modus 1"], a: 2, fb: "Die Logik ist das Gegenteil des Erwarteten: Weniger Transpositionen = stärkere innere Symmetrie (Modus 1: 2 Transpositionen, maximale Symmetrie). Mehr Transpositionen = schwächere Symmetrie. Eine gewöhnliche Leiter hat 12 verschiedene Transpositionen — keine besondere innere Symmetrie." },
  { q: "Welchen Effekt sucht Messiaen, wenn er in seinen Werken Modi mit begrenzten Transpositionen verwendet?", opts: ["Harmonische Spannung für eine dramatische Auflösung zu maximieren", "Eine einzigartige und unnachahmliche Farbe durch die innere Symmetrie des Modus zu erzeugen", "Bachs Barockpolyphonie wiederzufinden", "Die Musik für das breite Publikum zugänglich zu machen"], a: 1, fb: "Messiaen suchte explizit nach harmonischer 'Farbe' — jeder Modus mit begrenzten Transpositionen besitzt eine einzigartige und erkennbare Farbe. Sein katholischer Glaube führte ihn dazu, jedem Modus präzise visuelle Farben zuzuordnen (Synästhesie)." },
  { q: "Was ist 'modaler Austausch' (modale Entlehnung)?", opts: ["Den Modus innerhalb eines Stücks zu wechseln — von einem Modus zu einem anderen", "Gelegentlich einen Akkord von einem parallelen Modus oder der äolischen Tonleiter (natürliches Moll) zu entlehnen, während man in derselben Tonart bleibt", "Das gesamte Stück in einen anderen Modus zu transponieren", "Akkorde aus zwei verschiedenen Tonarten gleichzeitig zu verwenden (Bitonalität)"], a: 1, fb: "Modaler Austausch besteht darin, gelegentlich einen Akkord von einer anderen Leiter mit derselben Tonika zu entlehnen. In C-Dur kann man IVm (F-Moll) aus C-Moll, bVI (As) oder bVII (B) aus C-Äolisch entlehnen — ohne C als tonales Zentrum zu verlassen." },
  { q: "Der entlehnte IVm-Akkord in C-Dur ist:", opts: ["F–A–C (F-Dur)", "F–As–C (F-Moll)", "F–A–Cis (F übermäßig)", "F–As–Ces (F vermindert)"], a: 1, fb: "IVm in C-Dur = Mollakkord auf der 4. Stufe = F–As–C. Dieser Akkord wird aus C-Moll (oder Äolisch) entlehnt, wo A erniedrigt ist (As). Es ist eine der ausdrucksstärksten und häufigsten modalen Entlehnungen in Pop- und Jazzmusik." },
  { q: "Der bVII-Akkord in C-Dur (B–D–F) wird aus dem Modus entlehnt:", opts: ["C Dorisch", "C Phrygisch", "C Mixolydisch", "C Lydisch"], a: 2, fb: "Der Mixolydisch-Modus auf C (C–D–E–F–G–A–B) ist identisch mit C-Dur, aber mit B statt H. Der bVII-Akkord (B-Dur = B–D–F) ist im Mixolydisch-Modus natürlich. Sein Effekt ist charakteristisch für Rock und modale Musik." },
  { q: "Was ist der typische Effekt des bVI-Akkords (As in C-Dur) in einer Progression in C?", opts: ["Er klärt die Tonart C", "Er erzeugt eine romantische und expressive Farbe — eine sehr frappante Entlehnung", "Er entspricht einer Sekundärdominante", "Er kündigt stets eine Modulation an"], a: 1, fb: "Der bVI-Akkord (As–C–Es), aus C-Moll/Äolisch entlehnt, erzeugt eine plötzliche romantische und sehr expressive Farbe. Seine 'unerwartete' Farbe in einem Durkontext ist sehr frappant — häufig bei Schubert und in der Popmusik (z. B. der 'flat-six chord' der Rock-Balladen)." },
  { q: "Die Progression I–bVI–bVII–I in C-Dur verwendet Entlehnungen aus den Modi:", opts: ["Nur Dorisch und Phrygisch", "Äolisch (für bVI und bVII) und Mixolydisch (für bVII)", "Lydisch und Lokrisch", "Keine modale Entlehnung — das sind diatonische Akkorde von C-Dur"], a: 1, fb: "In C-Dur: bVI = As (aus C-Äolisch entlehnt, das As hat), bVII = B (aus C-Mixolydisch entlehnt, das B hat). Diese Progression (C–As–B–C) ist in Rock und Pop sehr häufig — sie kombiniert zwei verschiedene modale Geschmacksrichtungen." },
  { q: "Warum erzeugt modaler Austausch keine Modulation?", opts: ["Weil er nur Durakkorde verwendet", "Weil die Tonika dieselbe bleibt — die Entlehnung ist gelegentlich, nicht strukturell", "Weil er keinen Dominantakkord verwendet", "Weil er stets weniger als einen Takt dauert"], a: 1, fb: "Modaler Austausch ist eine gelegentliche Entlehnung — die Tonika ändert sich nicht. In C-Dur erzeugt die Entlehnung von As (bVI) eine Farbe, aber C bleibt das tonale Zentrum. Eine Modulation impliziert eine Änderung des tonalen Zentrums, bestätigt durch eine Kadenz in der neuen Tonart." },
  { q: "Messiaens Modus 3 hat 4 Transpositionen und 9 Töne. Seine Struktur ist:", opts: ["T–T–T–T–T–T–T–T (8 Ganztöne)", "T–½T–½T dreimal wiederholt (Gruppen von 3 Tönen)", "½T–T–½T–T viermal wiederholt", "T–½T–T–T–½T–T–T–½T–T"], a: 1, fb: "Messiaens Modus 3 ist auf Gruppen von 3 Tönen aufgebaut: T–½T–½T, dreimal wiederholt, um die Oktave zu überspannen. Seine Struktur ist C–D–Es–E–Fis–G–Gis–Ais–H. Er hat 4 verschiedene Transpositionen und eine chromatischere und dichtere Farbe als die Modi 1 und 2." },
  { q: "Welche Eigenschaft ist allen Modi mit begrenzten Transpositionen von Messiaen gemeinsam?", opts: ["Sie enthalten alle genau 6 Töne", "Sie haben alle eine innere Symmetrie, die bewirkt, dass bestimmte Transpositionen dieselbe Notensammlung erzeugen", "Sie sind alle von der Durtonleiter durch Weglassen von Tönen abgeleitet", "Sie sind alle auf Tritoni aufgebaut"], a: 1, fb: "Die grundlegende gemeinsame Eigenschaft aller Modi mit begrenzten Transpositionen ist ihre innere Symmetrie. Diese Symmetrie bewirkt, dass man nach einer bestimmten Anzahl von Transpositionen (weniger als 12) genau zu derselben Tonhöhensammlung zurückkehrt. Das ist das Kriterium, das sie von 'gewöhnlichen' Leitern unterscheidet." },
];

const questionsIt: Question[] = [
  // ── Argomento 1: Il planing (parallelismo) — 12 domande ──────────────────
  { q: "Che cos'è il planing nell'armonia impressionista?", opts: ["Una tecnica di risoluzione delle dissonanze", "Lo scivolamento di un accordo completo in moto parallelo senza risoluzione funzionale", "Una scala per toni interi", "Una progressione V–I caratteristica"], a: 1, fb: "Il planing è lo scivolamento di un accordo completo (con tutte le sue voci) in moto parallelo. Il colore dell'accordo si sposta senza che le tensioni si risolvano — l'effetto è quello di un 'blocco sonoro che scivola'." },
  { q: "Qual è la differenza tra il planing diatonico e il planing cromatico?", opts: ["Il planing diatonico usa semitoni, quello cromatico toni interi", "Il planing diatonico conserva lo stesso tipo di accordo su ogni grado della scala, quello cromatico traspone esattamente lo stesso accordo", "Il planing diatonico è tipico di Ravel, quello cromatico di Debussy", "Non c'è nessuna differenza — i due termini designano la stessa tecnica"], a: 1, fb: "Planing diatonico: gli accordi cambiano qualità secondo i gradi della scala (es. accordi di sesta in terze parallele). Planing cromatico: esattamente lo stesso accordo (stessa qualità) scivola cromaticamente — tutte le voci si muovono dello stesso intervallo." },
  { q: "Nel planing cromatico, cosa succede agli accordi quando si spostano?", opts: ["Cambiano qualità (maggiore → minore secondo il grado)", "Conservano esattamente la stessa struttura intervallare — cambia solo l'altezza", "Perdono le quinte per evitare i parallelismi", "Si risolvono verso la tonica ad ogni spostamento"], a: 1, fb: "Nel planing cromatico, l'accordo viene trasposto esattamente: se è un accordo di dominante con settima, rimane un accordo di dominante con settima ad ogni passo. La qualità è preservata, varia solo l'altezza." },
  { q: "Perché le quinte e ottave parallele sono tollerate nel planing?", opts: ["Perché sono rare nel planing", "Perché il planing funziona proprio su questo effetto di blocco sonoro parallelo — è intenzionale, non un errore", "Perché Debussy ignorava le regole del contrappunto", "Perché vengono compensate da dissonanze risolte"], a: 1, fb: "Il planing contraddice deliberatamente le regole del contrappunto classico. Le quinte parallele creano l'effetto di 'blocco' caratteristico — il suono scivola come un unico oggetto. È una scelta estetica, non negligenza." },
  { q: "Quale compositore è il maestro indiscusso del planing impressionista?", opts: ["César Franck", "Claude Debussy", "Johannes Brahms", "Ludwig van Beethoven"], a: 1, fb: "Claude Debussy è il creatore e maestro del planing impressionista. Il suo pezzo 'La Cathédrale engloutie' e i suoi preludi abbondano di accordi in moto parallelo che creano effetti di colore senza risoluzione funzionale." },
  { q: "Come si analizza il planing — con le funzioni T/SD/D o altrimenti?", opts: ["Con le funzioni classiche T/SD/D, come qualsiasi accordo tonale", "Per colore e registro: identificare l'accordo di partenza, annotare il movimento, descrivere l'effetto sonoro", "Solo tramite analisi schenkeriana", "Non si può analizzare il planing — è improvvisazione"], a: 1, fb: "L'analisi funzionale (T/SD/D) non si applica al planing: non c'è tensione-risoluzione nel senso classico. Si analizza per colore (tipo di accordo), registro (grave/acuto) ed effetto (fluttuamento, opacità, chiarezza)." },
  { q: "Nel planing diatonico, se si inizia su I (accordo maggiore), l'accordo su II sarà:", opts: ["Sempre maggiore", "Minore, perché II è minore nella scala maggiore", "Diminuito, perché II è diminuito", "Aumentato, perché la scala lo richiede"], a: 1, fb: "Nel planing diatonico, gli accordi seguono la qualità diatonica di ogni grado. In Do maggiore, II è Re minore (Re–Fa–La). Il planing diatonico preserva l'armatura — gli accordi cambiano qualità secondo il grado." },
  { q: "Il pezzo 'La Cathédrale engloutie' di Debussy usa massivamente:", opts: ["Dominanti secondarie classiche", "Accordi per quarte sovrapposte", "Accordi in planing parallelo per evocare campane sott'acqua", "Scale dodecafoniche"], a: 2, fb: "'La Cathédrale engloutie' impiega blocchi di accordi (spesso quinte e quarte) in moto parallelo per simulare risonanze di campane. Il planing crea l'effetto di immersione acquatica caratteristico del pezzo." },
  { q: "Il planing è apparso principalmente in quale corrente musicale?", opts: ["Il contrappunto barocco", "L'armonia romantica tedesca (Brahms, Wagner)", "L'impressionismo francese (Debussy, Ravel)", "Il dodecafonismo viennese (Schoenberg)"], a: 2, fb: "Il planing è una tecnica caratteristica dell'impressionismo francese, sviluppata da Debussy e Ravel alla fine del XIX e inizio del XX secolo. Si ispira alla musica giapponese (gamelan) e alle stampe orientali." },
  { q: "Nel planing, cosa sostituisce la funzione armonica classica?", opts: ["Il contrappunto rigoroso a 4 voci", "Il colore sonoro, il registro e il timbro dell'accordo", "La progressione per tritoni", "L'alternanza rigorosa minore/maggiore"], a: 1, fb: "Nell'armonia impressionista, il colore (qualità dell'accordo: maggiore, 7ª, 9ª), il registro (grave, medio, acuto) e il timbro (posizione aperta o chiusa) sostituiscono la logica tensione-risoluzione del sistema tonale." },
  { q: "Un accordo Maj7 nel planing cromatico che sale di un semitono diventa:", opts: ["Un accordo minore", "Lo stesso tipo di accordo Maj7 ma un semitono più alto", "Un accordo diminuito", "Un accordo di dominante settima"], a: 1, fb: "Nel planing cromatico, la struttura dell'accordo è preservata. Do Maj7 (Do–Mi–Sol–Si) trasposto un semitono più in alto dà Reb Maj7 (Reb–Fa–Lab–Do). Stessa struttura intervallare, altezza diversa." },
  { q: "Qual è la sensazione uditiva tipica del planing?", opts: ["Tensione crescente verso una risoluzione forte", "Uno scivolamento colorato senza direzione funzionale — come un acquerello sonoro", "Un rinforzo della tonalità principale", "Una dissoluzione verso il silenzio"], a: 1, fb: "Il planing crea una sensazione di scivolamento o fluttuamento — l'accordo si muove come un unico oggetto nello spazio sonoro. Non c'è direzione funzionale verso una risoluzione, solo uno spostamento di colore." },

  // ── Argomento 2: La scala per toni interi — 12 domande ───────────────────
  { q: "Quante note contiene la scala per toni interi?", opts: ["5 note", "6 note", "7 note", "8 note"], a: 1, fb: "La scala per toni interi contiene 6 note, tutte separate da un tono intero (2 semitoni). Esempio: Do–Re–Mi–Fa#–Sol#–La# (poi di nuovo Do). Esistono solo 2 scale per toni interi distinte (tutte le altre sono trasposizioni identiche all'una o all'altra)." },
  { q: "Qual è l'intervallo tra ogni nota della scala per toni interi?", opts: ["Un semitono (½T)", "Un tono intero (T)", "Una terza minore (T½)", "Un tritono"], a: 1, fb: "Ogni grado della scala per toni interi è separato dal successivo da un tono intero (2 semitoni). È questo che conferisce a questa scala la sua totale simmetria e l'assenza di nota sensibile." },
  { q: "Perché la scala per toni interi non contiene una nota sensibile?", opts: ["Per un errore di costruzione", "Perché tutti gli intervalli sono identici (toni interi) — nessun semitono crea tensione direzionale", "Perché è pentatonica", "Perché inizia su Do"], a: 1, fb: "La nota sensibile funziona grazie al semitono che crea tensione verso la tonica. Nella scala per toni interi, tutti gli intervalli sono toni interi — nessun semitono, quindi nessuna tensione direzionale, quindi nessuna nota sensibile. Il fluttuamento è totale." },
  { q: "Che tipo di accordo produce naturalmente la scala per toni interi?", opts: ["L'accordo perfetto maggiore (terza M + quinta giusta)", "L'accordo aumentato (terza M + terza M)", "L'accordo diminuito (terza m + terza m)", "L'accordo di dominante settima"], a: 1, fb: "La scala per toni interi produce accordi aumentati: sovrapponendo terze sui gradi della scala, si ottengono sistematicamente terze maggiori sovrapposte. Es.: Do–Mi–Sol# = accordo aumentato." },
  { q: "Quante trasposizioni distinte ha la scala per toni interi?", opts: ["6 trasposizioni distinte", "7 trasposizioni distinte", "Solo 2 trasposizioni distinte", "12 trasposizioni distinte"], a: 2, fb: "La scala per toni interi può essere trasposta solo in 2 modi distinti prima di tornare a sé stessa. Es.: Do–Re–Mi–Fa#–Sol#–La# e Reb–Mib–Fa–Sol–La–Si. Tutte le altre 'trasposizioni' riproducono una delle due scale." },
  { q: "Quale famoso preludio di Debussy è interamente costruito sulla scala per toni interi?", opts: ["Clair de Lune", "La Fille aux cheveux de lin", "Voiles", "La Cathédrale engloutie"], a: 2, fb: "'Voiles' (Préludes Libro I, 1909) è l'esempio più noto di pezzo interamente costruito sulla scala per toni interi. La sezione centrale impiega la pentatonica, creando un sorprendente contrasto di colore." },
  { q: "La scala per toni interi Do–Re–Mi–Fa#–Sol#–La# produce quale accordo su Do?", opts: ["Do maggiore (Do–Mi–Sol)", "Do aumentato (Do–Mi–Sol#)", "Do minore (Do–Mib–Sol)", "Do diminuito (Do–Mib–Solb)"], a: 1, fb: "Costruendo un accordo su Do nella scala per toni interi (Do–Re–Mi–Fa#–Sol#–La#), si prende Do, Mi (terza M), Sol# (terza M aggiuntiva) = Do aumentato. Tutti gli accordi di questa scala sono aumentati." },
  { q: "Qual è il colore sonoro caratteristico della scala per toni interi?", opts: ["Tensione forte, destabilizzante, risoluzione urgente", "Fluttuamento, dissoluzione tonale, mistero onirico", "Chiarezza diatonica, struttura solida", "Violenza ritmica, colore slavo"], a: 1, fb: "La scala per toni interi crea un totale fluttuamento tonale — senza nota sensibile, senza semitono, l'orecchio non riesce ad orientarsi verso nessuna tonica. L'effetto è onirico, misterioso, dissolto — esattamente l'estetica impressionista di Debussy." },
  { q: "La scala per toni interi è chiamata anche il modo __ di Messiaen.", opts: ["Modo 2", "Modo 3", "Modo 1", "Modo 4"], a: 2, fb: "Messiaen sistematizzò le scale simmetriche nel suo trattato 'Tecnica del mio linguaggio musicale' (1944). La scala per toni interi è il suo Modo 1 — il più semplice, con solo 2 trasposizioni possibili." },
  { q: "Tra la scala per toni interi su Do e quella su Reb, quante note sono in comune?", opts: ["Nessuna nota in comune", "3 note in comune", "Tutte le note — sono le stesse", "Solo 1 nota in comune"], a: 0, fb: "Le due scale per toni interi distinte (Do–Re–Mi–Fa#–Sol#–La# e Reb–Mib–Fa–Sol–La–Si) non hanno nessuna nota in comune (a parte le enarmoniche). Insieme condividono tutti i 12 semitoni." },
  { q: "Perché si può dire che la scala per toni interi è 'perfettamente simmetrica'?", opts: ["Perché ha 7 gradi come la scala maggiore", "Perché tutti i suoi intervalli sono identici — può essere letta da qualsiasi grado e restituisce la stessa scala", "Perché contiene un tritono al suo centro", "Perché alterna toni e semitoni"], a: 1, fb: "La simmetria perfetta della scala per toni interi deriva dall'uniformità dei suoi intervalli. Indipendentemente dalla nota di partenza nella scala, la successione degli intervalli è identica (T–T–T–T–T–T). Questa è una proprietà che la scala maggiore non possiede." },
  { q: "In un contesto pedagogico, come si distingue la scala per toni interi dalla scala pentatonica?", opts: ["Sono intercambiabili — stesso effetto sonoro", "La scala per toni interi ha 6 note, fluttuamento totale, accordi aumentati; la pentatonica ha 5 note, serenità, nessun accordo di dominante", "La scala per toni interi è maggiore, la pentatonica è minore", "La scala per toni interi viene dall'Asia, la pentatonica dalla Francia"], a: 1, fb: "Distinzione essenziale: scala per toni interi = 6 note, solo toni interi, fluttuamento tonale, accordi aumentati. Pentatonica = 5 note, senza semitoni ma non sempre toni interi (T–T–T½–T–T½), serenità, colore orientale/folk." },

  // ── Argomento 3: La scala octatonica — 12 domande ────────────────────────
  { q: "Quante note contiene la scala octatonica?", opts: ["6 note", "7 note", "8 note", "9 note"], a: 2, fb: "La scala octatonica ('octa' = 8) contiene 8 note per ottava. Esempio: Do–Re–Mib–Fa–Fa#–Sol#–La–Si–Do. Alterna tono e semitono (o semitono e tono a seconda della versione)." },
  { q: "Qual è il principio di costruzione della scala octatonica?", opts: ["Solo toni interi", "Alternanza tono–semitono (o semitono–tono)", "Solo semitoni", "Terza minore + semitono in alternanza"], a: 1, fb: "La scala octatonica alterna rigorosamente tono e semitono (T–½T–T–½T–T–½T–T–½T) o l'inverso (½T–T–½T–T–½T–T–½T–T). Questa simmetria crea esattamente 8 note per ottava." },
  { q: "Quale accordo caratteristico si trova naturalmente nella scala octatonica?", opts: ["L'accordo aumentato", "L'accordo di dominante settima", "L'accordo diminuito di settima (dim7)", "L'accordo di sesta napoletana"], a: 2, fb: "La scala octatonica contiene 3 accordi diminuiti di settima (dim7): Do–Mib–Fa#–La, Re–Fa–Sol#–Si, e Mib–Fa#–La–Do. È la scala ideale per costruire sequenze di accordi dim7." },
  { q: "Quante trasposizioni distinte ha la scala octatonica?", opts: ["2 trasposizioni", "3 trasposizioni", "4 trasposizioni", "12 trasposizioni"], a: 1, fb: "La scala octatonica ha solo 3 trasposizioni distinte. Dopo 3 trasposizioni di un semitono, si ritorna alla stessa collezione di note. È il Modo 2 di Messiaen, con esattamente 3 trasposizioni." },
  { q: "Quale compositore russo usò massivamente la scala octatonica nei suoi balletti?", opts: ["Sergej Rachmaninov", "Pjotr Il'ič Čajkovskij", "Igor Stravinskij", "Dmitrij Šostakovič"], a: 2, fb: "Igor Stravinskij è il maestro della scala octatonica, che impiega nei suoi grandi balletti (L'Uccello di fuoco, Petruška, La sagra della primavera). Gli conferisce quel caratteristico colore 'slavo mistico'." },
  { q: "Quale compositore francese teorizzò la scala octatonica come 'Modo 2 a trasposizioni limitate'?", opts: ["Claude Debussy", "Maurice Ravel", "Olivier Messiaen", "Gabriel Fauré"], a: 2, fb: "Olivier Messiaen sistematizzò le scale simmetriche in 'Tecnica del mio linguaggio musicale' (1944). Chiamò la scala octatonica 'Modo 2 a trasposizioni limitate' — 3 trasposizioni possibili contro 2 per il Modo 1." },
  { q: "La scala octatonica Do–Re–Mib–Fa–Fa#–Sol#–La–Si contiene quanti accordi diminuiti di settima distinti?", opts: ["1 accordo dim7", "2 accordi dim7", "3 accordi dim7", "4 accordi dim7"], a: 2, fb: "Ogni scala octatonica contiene esattamente 3 accordi dim7 intrecciati. In Do–Re–Mib–Fa–Fa#–Sol#–La–Si: (1) Do–Mib–Fa#–La, (2) Re–Fa–Sol#–Si, e (3) Mib–Fa#–La–Do. Questi tre accordi coprono tutti i 12 suoni cromatici." },
  { q: "Qual è il colore sonoro caratteristico della scala octatonica?", opts: ["Fluttuamento onirico senza tensione", "Tensione simmetrica, mistero, instabilità organizzata", "Serenità, colore orientale", "Chiarezza tonale diatonica"], a: 1, fb: "La scala octatonica crea una particolare tensione simmetrica — gli accordi dim7 creano instabilità ma in modo ordinato. Il colore è scuro, misterioso, teso — caratteristico dello stile slavo mistico di Stravinskij e dello splendore di Messiaen." },
  { q: "La scala octatonica differisce dalla scala per toni interi in quanto:", opts: ["La scala octatonica ha 6 note, quella per toni interi ne ha 8", "La scala octatonica alterna tono e semitono (8 note), quella per toni interi ha solo toni interi (6 note)", "Sono identiche — due nomi per la stessa scala", "La scala octatonica viene dalla Russia, quella per toni interi dalla Francia"], a: 1, fb: "Differenza fondamentale: scala per toni interi = 6 note, solo toni interi, accordi aumentati. Scala octatonica = 8 note, alternanza tono/semitono, accordi dim7. Due colori molto distinti nonostante la simmetria comune." },
  { q: "In 'Petruška' di Stravinskij, l'accordo 'bitonale' (Do maggiore + Fa# maggiore simultaneamente) è possibile grazie a:", opts: ["La scala pentatonica", "La scala per toni interi", "La scala octatonica", "Il sistema dodecafonico"], a: 2, fb: "L'accordo 'Petruška' (Do–Mi–Sol + Fa#–La#–Do#) è reso coerente dalla scala octatonica che contiene entrambi gli insiemi di note simultaneamente. La simmetria octatonica consente questa caratteristica bitonalità." },
  { q: "Perché l'accordo diminuito di settima (dim7) è particolarmente ambiguo tonalmente?", opts: ["Perché contiene un tritono", "Perché è composto di terze minori uguali — può risolvere verso 4 tonalità diverse", "Perché è troppo dissonante per risolvere", "Perché non appartiene a nessuna scala"], a: 1, fb: "L'accordo dim7 è composto da 4 terze minori sovrapposte (Do–Mib–Fa#–La). Poiché tutte le sue terze sono uguali, è perfettamente simmetrico e può risolvere verso 4 diverse tonalità maggiori o minori — da qui la sua estrema ambiguità tonale." },
  { q: "La scala octatonica è chiamata 'Modo 2' da Messiaen perché:", opts: ["È la seconda scala che ha inventato", "È la scala con 2 trasposizioni distinte", "È il secondo modo nella sua classificazione dei modi a trasposizioni limitate (dopo la scala per toni interi)", "È la scala che inizia sul 2° grado"], a: 2, fb: "Messiaen numerò i suoi modi secondo la loro complessità e il numero di trasposizioni. Modo 1 (2 trasposizioni) = scala per toni interi. Modo 2 (3 trasposizioni) = scala octatonica. La numerazione segue un ordine logico nel suo sistema." },

  // ── Argomento 4: La scala pentatonica — 12 domande ───────────────────────
  { q: "Quante note contiene la scala pentatonica?", opts: ["4 note", "5 note", "6 note", "7 note"], a: 1, fb: "La scala pentatonica ('penta' = 5) contiene 5 note. La versione più comune su Do è: Do–Re–Mi–Sol–La. Si ottiene sopprimendo il Fa e il Si dalla scala di Do maggiore." },
  { q: "Cosa caratterizza la scala pentatonica rispetto alla scala maggiore?", opts: ["Contiene più semitoni", "Non contiene nessun semitono — il che elimina qualsiasi tensione direzionale", "Contiene un tritono centrale", "È sempre minore"], a: 1, fb: "La scala pentatonica maggiore Do–Re–Mi–Sol–La non contiene nessun semitono. L'assenza di semitono significa assenza di nota sensibile e di tritono — quindi nessuna tensione direzionale verso una risoluzione. Il suono è sereno, aperto." },
  { q: "Quale nota è assente dalla pentatonica Do–Re–Mi–Sol–La rispetto a Do maggiore?", opts: ["Re e Sol", "Fa e Si", "Mi e La", "Sol e Do"], a: 1, fb: "La scala di Do maggiore è Do–Re–Mi–Fa–Sol–La–Si–Do. Sopprimendo il Fa e il Si (le due note che formano il tritono e creano la tensione sensibile-tonica), si ottiene la pentatonica Do–Re–Mi–Sol–La." },
  { q: "Perché la scala pentatonica è universale — presente in quasi tutte le culture musicali?", opts: ["Perché gli antichi Greci l'hanno imposta al mondo", "Perché è facile da suonare su qualsiasi strumento", "Perché l'assenza di semitono la rende naturalmente consonante e universalmente accessibile", "Perché le 5 dita della mano corrispondono alle 5 note"], a: 2, fb: "L'assenza di semitono nella scala pentatonica la rende naturalmente gradevole all'orecchio umano — nessuna nota crea tensione verso una risoluzione. È questa proprietà di consonanza naturale che spiega la sua presenza nelle musiche di Africa, Asia, America ed Europa." },
  { q: "La scala pentatonica è usata nella musica impressionista per evocare:", opts: ["La complessità dell'armonia romantica tedesca", "Il colore orientale, esotico o antico (gamelan, musica cinese)", "Il contrappunto barocco rigoroso", "La danza folk irlandese"], a: 1, fb: "Debussy scoprì il gamelan giavanese all'Esposizione Universale del 1889. Affascinato dal colore pentatonico di questa musica, lo integrò nel suo linguaggio impressionista per evocare l'Oriente, il sogno e l'esotismo." },
  { q: "Qual è il rapporto tra la pentatonica e il jazz?", opts: ["Il jazz evita sistematicamente la pentatonica", "La pentatonica (soprattutto minore) è una delle basi del jazz e del blues", "Il jazz usa solo la pentatonica — mai le altre scale", "La pentatonica è esclusiva della musica classica"], a: 1, fb: "La scala pentatonica minore (Do–Mib–Fa–Sol–Sib) è al cuore del blues e del jazz. Permette di suonare 'a orecchio' su qualsiasi accordo senza dissonanza — da qui la sua onnipresenza negli assoli di improvvisazione jazz e blues." },
  { q: "La pentatonica minore su La è:", opts: ["La–Si–Do–Mi–Fa#", "La–Do–Re–Mi–Sol", "La–Sib–Do–Reb–Mib", "La–Si–Re–Mi–Sol#"], a: 1, fb: "La pentatonica minore su La è La–Do–Re–Mi–Sol. Struttura: T½–T–T–T½–T. Corrisponde alla pentatonica maggiore di Do (Do–Re–Mi–Sol–La) ma letta da La — entrambe condividono esattamente le stesse note." },
  { q: "In 'Voiles' di Debussy, la sezione centrale usa la pentatonica per creare:", opts: ["Un contrasto di colore con la scala per toni interi della sezione principale", "Una tensione massima prima della risoluzione finale", "Un ritorno alla tonalità di Do maggiore", "Un effetto di fuga barocca"], a: 0, fb: "'Voiles' è costruita sulla scala per toni interi (Do–Re–Mi–Fa#–Sol#–La#) nelle sezioni A. La sezione centrale (B) usa la pentatonica (Sol#–La#–Do–Re–Mi) — questo contrasto di colore è un colpo di genio: due scale senza semitoni, due colori radicalmente diversi." },
  { q: "La pentatonica è spesso usata nella musica folk e nei canti tradizionali perché:", opts: ["È più facile da memorizzare con sole 5 note", "L'assenza di semitono consente un'intonazione più semplice e adattabilità a voci diverse", "I musicisti tradizionali ignoravano le scale a 7 note", "Corrisponde esattamente ai modi gregoriani"], a: 1, fb: "L'assenza di semitono nella pentatonica la rende particolarmente adatta al canto tradizionale: nessuna tensione d'intonazione sui semitoni, adattabile a registri diversi, naturalmente consonante tra più voci." },
  { q: "Quante trasposizioni distinte ha la scala pentatonica?", opts: ["5 trasposizioni distinte", "7 trasposizioni distinte", "12 trasposizioni distinte", "2 trasposizioni distinte"], a: 2, fb: "La scala pentatonica ha 12 trasposizioni distinte — non è un 'modo a trasposizioni limitate'. Contrariamente alla scala per toni interi (2) o all'octatonica (3), la pentatonica può essere trasposta 12 volte senza tornare a sé stessa prima dell'ottava." },
  { q: "Qual è l'accordo di dominante nella scala pentatonica Do–Re–Mi–Sol–La?", opts: ["Sol–Si–Re (V maggiore)", "Sol–Sib–Re (V minore)", "Non esiste accordo di dominante in senso funzionale — Si e Fa sono assenti", "Sol–La–Re (accordo di quinta aggiunta)"], a: 2, fb: "La scala pentatonica non contiene Si (sensibile) né Fa. Tuttavia l'accordo di dominante V7 (Sol–Si–Re–Fa) richiede esattamente queste due note. Senza sensibile, nessuna tensione funzionale verso I — è proprio questo che conferisce alla pentatonica il suo carattere senza risoluzione." },
  { q: "Quale differenza fondamentale esiste tra la pentatonica e la scala per toni interi sul piano del colore?", opts: ["La pentatonica suona più 'moderna' della scala per toni interi", "La scala per toni interi crea il fluttuamento/mistero aumentato, la pentatonica crea la serenità/chiarezza senza tensione", "La pentatonica è più dissonante della scala per toni interi", "Non c'è differenza di colore — entrambe sono 'impressioniste'"], a: 1, fb: "Scala per toni interi: fluttuamento misterioso e dissoluzione tonale (accordi aumentati, nessuna nota sensibile). Pentatonica: serenità e chiarezza senza tensione (consonanze naturali, colore folk o orientale). Due colori distinti nonostante l'assenza comune di semitoni." },

  // ── Argomento 5: Modi di Messiaen e interscambio modale — 12 domande ─────
  { q: "Che cos'è un 'modo a trasposizioni limitate' secondo Messiaen?", opts: ["Un modo che non può essere trasposto", "Un modo le cui trasposizioni successive riproducono collezioni di note identiche prima di aver percorso tutti i 12 semitoni", "Un modo usato solo nella liturgia", "Un modo limitato a 5 note"], a: 1, fb: "Un modo a trasposizioni limitate è una scala la cui simmetria interna fa sì che certe trasposizioni riproducano esattamente la stessa collezione di note. Es.: la scala per toni interi su Do e su Re sono due scale distinte, ma su Mi torna a Do — quindi solo 2 trasposizioni reali." },
  { q: "Quanti modi a trasposizioni limitate ha catalogato Messiaen nel suo trattato del 1944?", opts: ["3 modi", "5 modi", "7 modi", "12 modi"], a: 2, fb: "Messiaen catalogò 7 modi a trasposizioni limitate in 'Tecnica del mio linguaggio musicale' (1944). Ogni modo è caratterizzato dalla sua struttura intervallare, dal suo numero di trasposizioni e dal suo particolare 'colore'." },
  { q: "Il Modo 1 di Messiaen ha 2 trasposizioni e il Modo 2 ne ha 3. Cosa significa questo numero crescente?", opts: ["Che il Modo 2 è più complesso e più dissonante", "Che più trasposizioni ci sono, più debole è la simmetria interna", "Più trasposizioni distinte ha un modo, più si avvicina a una scala ordinaria — la simmetria si indebolisce", "Che il Modo 2 copre più tonalità del Modo 1"], a: 2, fb: "La logica è l'inverso di ciò che si crede: meno trasposizioni = maggiore simmetria interna (Modo 1: 2 trasposizioni, simmetria massima). Più trasposizioni = simmetria più debole. Una scala ordinaria ha 12 trasposizioni distinte — nessuna simmetria interna particolare." },
  { q: "Quale effetto cerca Messiaen quando usa i modi a trasposizioni limitate nelle sue opere?", opts: ["Massimizzare la tensione armonica per una risoluzione drammatica", "Creare un colore unico e inimitabile attraverso la simmetria interna del modo", "Ritrovare il contrappunto barocco di Bach", "Rendere la musica accessibile al grande pubblico"], a: 1, fb: "Messiaen cercava esplicitamente il 'colore' armonico — ogni modo a trasposizioni limitate possiede un colore unico e riconoscibile. La sua fede cattolica lo portò ad associare colori visivi precisi a ogni modo (sinestesia)." },
  { q: "Che cos'è l'interscambio modale (prestito modale)?", opts: ["Cambiare modo all'interno di un pezzo — passare da un modo a un altro", "Prendere in prestito un accordo da un modo parallelo o dalla scala eolia (minore naturale) rimanendo nella stessa tonalità", "Trasporre l'intero pezzo in un altro modo", "Usare accordi di due tonalità diverse simultaneamente (bitonalità)"], a: 1, fb: "L'interscambio modale consiste nel prendere in prestito puntualmente un accordo da un'altra scala basata sulla stessa tonica. In Do maggiore, si può prendere in prestito IVm (Fa minore) dal Do minore, bVI (Lab) o bVII (Sib) dal Do eolico — senza lasciare Do come centro tonale." },
  { q: "L'accordo IVm preso in prestito in Do maggiore è:", opts: ["Fa–La–Do (Fa maggiore)", "Fa–Lab–Do (Fa minore)", "Fa–La–Do# (Fa aumentato)", "Fa–Lab–Dob (Fa diminuito)"], a: 1, fb: "IVm in Do maggiore = accordo minore sul 4° grado = Fa–Lab–Do. Questo accordo viene preso in prestito dal Do minore (o eolico) dove il La è abbassato (Lab). È uno dei prestiti modali più espressivi e frequenti nella musica pop e jazz." },
  { q: "L'accordo bVII in Do maggiore (Sib–Re–Fa) viene preso in prestito dal modo:", opts: ["Do dorico", "Do frigio", "Do misolidio", "Do lidio"], a: 2, fb: "Il modo misolidio su Do (Do–Re–Mi–Fa–Sol–La–Sib) è identico a Do maggiore ma con un Sib invece di Si. L'accordo bVII (Sib maggiore = Sib–Re–Fa) è naturale nel modo misolidio. Il suo effetto è caratteristico del rock e della musica modale." },
  { q: "Qual è l'effetto tipico dell'accordo bVI (Lab in Do maggiore) in una progressione in Do?", opts: ["Chiarisce la tonalità di Do", "Crea un colore romantico ed espressivo — un prestito molto sorprendente", "È equivalente a una dominante secondaria", "Annuncia sempre una modulazione"], a: 1, fb: "L'accordo bVI (Lab–Do–Mib) preso in prestito dal Do minore/eolico crea un colore romantico improvviso e molto espressivo. Il suo colore 'inatteso' in un contesto maggiore è molto sorprendente — frequente in Schubert e nella musica pop (es. il 'flat-six chord' delle ballate rock)." },
  { q: "La progressione I–bVI–bVII–I in Do maggiore usa prestiti dai modi:", opts: ["Dorico e frigio soltanto", "Eolico (per bVI e bVII) e misolidio (per bVII)", "Lidio e locrio", "Nessun prestito modale — sono accordi diatonici di Do maggiore"], a: 1, fb: "In Do maggiore: bVI = Lab (preso dal Do eolico che ha Lab), bVII = Sib (preso dal Do misolidio che ha Sib). Questa progressione (Do–Lab–Sib–Do) è molto frequente nel rock e nel pop — combina due sapori modali distinti." },
  { q: "Perché l'interscambio modale non crea una modulazione?", opts: ["Perché usa solo accordi maggiori", "Perché la tonica rimane la stessa — il prestito è puntuale, non strutturale", "Perché non usa nessun accordo di dominante", "Perché dura sempre meno di una battuta"], a: 1, fb: "L'interscambio modale è un prestito puntuale — la tonica non cambia. In Do maggiore, prendere in prestito Lab (bVI) crea un colore, ma Do rimane il centro tonale. Una modulazione implica un cambiamento di centro tonale confermato da una cadenza nella nuova tonalità." },
  { q: "Il Modo 3 di Messiaen ha 4 trasposizioni e 9 note. La sua struttura è:", opts: ["T–T–T–T–T–T–T–T (8 toni interi)", "T–½T–½T ripetuto 3 volte (gruppi di 3 note)", "½T–T–½T–T ripetuto 4 volte", "T–½T–T–T–½T–T–T–½T–T"], a: 1, fb: "Il Modo 3 di Messiaen è costruito su gruppi di 3 note: T–½T–½T, ripetuto 3 volte per coprire l'ottava. La sua struttura è Do–Re–Mib–Mi–Fa#–Sol–Sol#–La#–Si. Ha 4 trasposizioni distinte e un colore più cromatico e denso dei Modi 1 e 2." },
  { q: "Quale proprietà è comune a tutti i modi a trasposizioni limitate di Messiaen?", opts: ["Contengono tutti esattamente 6 note", "Hanno tutti una simmetria interna che fa sì che certe trasposizioni producano la stessa collezione di note", "Derivano tutti dalla scala maggiore per soppressione di note", "Sono tutti costruiti su tritoni"], a: 1, fb: "La proprietà fondamentale comune a tutti i modi a trasposizioni limitate è la loro simmetria interna. Questa simmetria fa sì che, dopo un certo numero di trasposizioni (meno di 12), si torni esattamente alla stessa collezione di altezze. È il criterio che li distingue dalle scale 'ordinarie'." },
];

const questionsPt: Question[] = [
  // ── Tópico 1: O planing (paralelismo) — 12 perguntas ─────────────────────
  { q: "O que é o planing na harmonia impressionista?", opts: ["Uma técnica de resolução de dissonâncias", "O deslizamento de um acorde completo em movimento paralelo sem resolução funcional", "Uma escala de tons inteiros", "Uma progressão V–I característica"], a: 1, fb: "O planing é o deslizamento de um acorde completo (com todas as suas vozes) em movimento paralelo. A cor do acorde se desloca sem que as tensões se resolvam — o efeito é o de um 'bloco sonoro que desliza'." },
  { q: "Qual é a diferença entre o planing diatônico e o planing cromático?", opts: ["O planing diatônico usa semitons, o cromático usa tons inteiros", "O planing diatônico conserva o mesmo tipo de acorde em cada grau da escala, o cromático transpõe exatamente o mesmo acorde", "O planing diatônico é próprio de Ravel, o cromático de Debussy", "Não há nenhuma diferença — os dois termos designam a mesma técnica"], a: 1, fb: "Planing diatônico: os acordes mudam de qualidade segundo os graus da escala (ex. acordes de sexta em terças paralelas). Planing cromático: exatamente o mesmo acorde (mesma qualidade) desliza cromaticamente — todas as vozes se movem pelo mesmo intervalo." },
  { q: "No planing cromático, o que acontece com os acordes quando se deslocam?", opts: ["Mudam de qualidade (maior → menor segundo o grau)", "Conservam exatamente a mesma estrutura intervalar — só muda a altura", "Perdem as quintas para evitar os paralelismos", "Resolvem-se para a tônica a cada deslocamento"], a: 1, fb: "No planing cromático, o acorde é transposto exatamente: se é um acorde de dominante com sétima, continua sendo um acorde de dominante com sétima a cada passo. A qualidade é preservada, só varia a altura." },
  { q: "Por que as quintas e oitavas paralelas são toleradas no planing?", opts: ["Porque são raras no planing", "Porque o planing funciona precisamente sobre esse efeito de bloco sonoro paralelo — é intencional, não um erro", "Porque Debussy ignorava as regras do contraponto", "Porque são compensadas por dissonâncias resolvidas"], a: 1, fb: "O planing contradiz deliberadamente as regras do contraponto clássico. As quintas paralelas criam o efeito de 'bloco' característico — o som desliza como um único objeto. É uma escolha estética, não negligência." },
  { q: "Qual compositor é o mestre indiscutível do planing impressionista?", opts: ["César Franck", "Claude Debussy", "Johannes Brahms", "Ludwig van Beethoven"], a: 1, fb: "Claude Debussy é o criador e mestre do planing impressionista. Sua peça 'La Cathédrale engloutie' e seus prelúdios estão repletos de acordes em movimento paralelo que criam efeitos de cor sem resolução funcional." },
  { q: "Como analisar o planing — com as funções T/SD/D ou de outra forma?", opts: ["Com as funções clássicas T/SD/D, como qualquer acorde tonal", "Por cor e registro: identificar o acorde de partida, anotar o movimento, descrever o efeito sonoro", "Somente por análise schenkeriana", "Não se pode analisar o planing — é improvisação"], a: 1, fb: "A análise funcional (T/SD/D) não se aplica ao planing: não há tensão-resolução no sentido clássico. Analisa-se por cor (tipo de acorde), registro (grave/agudo) e efeito (flutuação, opacidade, clareza)." },
  { q: "No planing diatônico, se começamos em I (acorde maior), o acorde em II será:", opts: ["Sempre maior", "Menor, porque II é menor na escala maior", "Diminuto, porque II é diminuto", "Aumentado, porque a escala o exige"], a: 1, fb: "No planing diatônico, os acordes seguem a qualidade diatônica de cada grau. Em Dó maior, II é Ré menor (Ré–Fá–Lá). O planing diatônico preserva a armadura — os acordes mudam de qualidade segundo o grau." },
  { q: "A peça 'La Cathédrale engloutie' de Debussy usa maciçamente:", opts: ["Dominantes secundárias clássicas", "Acordes de quartas sobrepostas", "Acordes em planing paralelo para evocar sinos sob a água", "Escalas dodecafônicas"], a: 2, fb: "'La Cathédrale engloutie' emprega blocos de acordes (frequentemente quintas e quartas) em movimento paralelo para simular ressonâncias de sinos. O planing cria o efeito característico de imersão aquática da peça." },
  { q: "O planing apareceu principalmente em qual corrente musical?", opts: ["O contraponto barroco", "A harmonia romântica alemã (Brahms, Wagner)", "O impressionismo francês (Debussy, Ravel)", "O dodecafonismo vienense (Schoenberg)"], a: 2, fb: "O planing é uma técnica característica do impressionismo francês, desenvolvida por Debussy e Ravel no final do século XIX e início do XX. Inspira-se na música japonesa (gamelan) e nas estampas orientais." },
  { q: "No planing, o que substitui a função harmônica clássica?", opts: ["O contraponto rigoroso a 4 vozes", "A cor sonora, o registro e o timbre do acorde", "A progressão por tritonos", "A alternância rigorosa menor/maior"], a: 1, fb: "Na harmonia impressionista, a cor (qualidade do acorde: maior, 7ª, 9ª), o registro (grave, médio, agudo) e o timbre (posição aberta ou fechada) substituem a lógica tensão-resolução do sistema tonal." },
  { q: "Um acorde Maj7 no planing cromático que sobe um semitom torna-se:", opts: ["Um acorde menor", "O mesmo tipo de acorde Maj7 mas um semitom mais alto", "Um acorde diminuto", "Um acorde de dominante sétima"], a: 1, fb: "No planing cromático, a estrutura do acorde é preservada. Dó Maj7 (Dó–Mi–Sol–Si) transposto um semitom mais alto dá Réb Maj7 (Réb–Fá–Láb–Dó). Mesma estrutura intervalar, altura diferente." },
  { q: "Qual é a sensação auditiva típica do planing?", opts: ["Tensão crescente em direção a uma resolução forte", "Um deslizamento colorido sem direção funcional — como uma aquarela sonora", "Um reforço da tonalidade principal", "Uma dissolução em direção ao silêncio"], a: 1, fb: "O planing cria uma sensação de deslizamento ou flutuação — o acorde se move como um único objeto no espaço sonoro. Não há direção funcional em direção a uma resolução, apenas um deslocamento de cor." },

  // ── Tópico 2: A escala de tons inteiros — 12 perguntas ───────────────────
  { q: "Quantas notas contém a escala de tons inteiros?", opts: ["5 notas", "6 notas", "7 notas", "8 notas"], a: 1, fb: "A escala de tons inteiros contém 6 notas, todas separadas por um tom inteiro (2 semitons). Exemplo: Dó–Ré–Mi–Fá#–Sol#–Lá# (depois de volta a Dó). Existem apenas 2 escalas de tons inteiros distintas (as demais são transposições idênticas a uma ou outra)." },
  { q: "Qual é o intervalo entre cada nota da escala de tons inteiros?", opts: ["Um semitom (½T)", "Um tom inteiro (T)", "Uma terça menor (T½)", "Um tritono"], a: 1, fb: "Cada grau da escala de tons inteiros é separado do seguinte por um tom inteiro (2 semitons). É isso que confere a essa escala sua simetria total e a ausência de nota sensível." },
  { q: "Por que a escala de tons inteiros não contém uma nota sensível?", opts: ["Por um erro de construção", "Porque todos os intervalos são idênticos (tons inteiros) — nenhum semitom cria tensão direcional", "Porque é pentatônica", "Porque começa em Dó"], a: 1, fb: "A nota sensível funciona graças ao semitom que cria tensão em direção à tônica. Na escala de tons inteiros, todos os intervalos são tons inteiros — nenhum semitom, portanto nenhuma tensão direcional, portanto nenhuma nota sensível. A flutuação é total." },
  { q: "Que tipo de acorde produz naturalmente a escala de tons inteiros?", opts: ["O acorde perfeito maior (terça M + quinta justa)", "O acorde aumentado (terça M + terça M)", "O acorde diminuto (terça m + terça m)", "O acorde de dominante sétima"], a: 1, fb: "A escala de tons inteiros produz acordes aumentados: sobrepondo terças nos graus da escala, obtêm-se sistematicamente terças maiores superpostas. Ex.: Dó–Mi–Sol# = acorde aumentado." },
  { q: "Quantas transposições distintas tem a escala de tons inteiros?", opts: ["6 transposições distintas", "7 transposições distintas", "Apenas 2 transposições distintas", "12 transposições distintas"], a: 2, fb: "A escala de tons inteiros só pode ser transposta de 2 maneiras distintas antes de retornar a si mesma. Ex.: Dó–Ré–Mi–Fá#–Sol#–Lá# e Réb–Mib–Fá–Sol–Lá–Si. Todas as outras 'transposições' reproduzem uma das duas escalas." },
  { q: "Qual famoso prelúdio de Debussy é inteiramente construído sobre a escala de tons inteiros?", opts: ["Clair de Lune", "La Fille aux cheveux de lin", "Voiles", "La Cathédrale engloutie"], a: 2, fb: "'Voiles' (Préludes Livro I, 1909) é o exemplo mais conhecido de peça inteiramente construída sobre a escala de tons inteiros. A seção central emprega a pentatônica, criando um surpreendente contraste de cor." },
  { q: "A escala de tons inteiros Dó–Ré–Mi–Fá#–Sol#–Lá# produz qual acorde em Dó?", opts: ["Dó maior (Dó–Mi–Sol)", "Dó aumentado (Dó–Mi–Sol#)", "Dó menor (Dó–Mib–Sol)", "Dó diminuto (Dó–Mib–Solb)"], a: 1, fb: "Construindo um acorde em Dó na escala de tons inteiros (Dó–Ré–Mi–Fá#–Sol#–Lá#), toma-se Dó, Mi (terça M), Sol# (terça M adicional) = Dó aumentado. Todos os acordes desta escala são aumentados." },
  { q: "Qual é a cor sonora característica da escala de tons inteiros?", opts: ["Tensão forte, desestabilizante, resolução urgente", "Flutuação, dissolução tonal, mistério onírico", "Clareza diatônica, estrutura sólida", "Violência rítmica, cor eslava"], a: 1, fb: "A escala de tons inteiros cria uma flutuação tonal total — sem nota sensível, sem semitom, o ouvido não consegue se orientar em direção a nenhuma tônica. O efeito é onírico, misterioso, dissolvido — exatamente a estética impressionista de Debussy." },
  { q: "A escala de tons inteiros também é chamada de modo __ de Messiaen.", opts: ["Modo 2", "Modo 3", "Modo 1", "Modo 4"], a: 2, fb: "Messiaen sistematizou as escalas simétricas em seu tratado 'Técnica da minha linguagem musical' (1944). A escala de tons inteiros é o seu Modo 1 — o mais simples, com apenas 2 transposições possíveis." },
  { q: "Entre a escala de tons inteiros em Dó e a escala de tons inteiros em Réb, quantas notas são comuns?", opts: ["Nenhuma nota em comum", "3 notas em comum", "Todas as notas — são as mesmas", "Apenas 1 nota em comum"], a: 0, fb: "As duas escalas de tons inteiros distintas (Dó–Ré–Mi–Fá#–Sol#–Lá# e Réb–Mib–Fá–Sol–Lá–Si) não têm nenhuma nota em comum (desconsiderando as enarmônicas). Juntas, compartilham todos os 12 semitons." },
  { q: "Por que se pode dizer que a escala de tons inteiros é 'perfeitamente simétrica'?", opts: ["Porque tem 7 graus como a escala maior", "Porque todos os seus intervalos são idênticos — pode ser lida a partir de qualquer grau e dar a mesma escala", "Porque contém um tritono em seu centro", "Porque alterna tons e semitons"], a: 1, fb: "A simetria perfeita da escala de tons inteiros provém da uniformidade de seus intervalos. Independentemente da nota de partida na escala, a sucessão de intervalos é idêntica (T–T–T–T–T–T). Esta é uma propriedade que a escala maior não possui." },
  { q: "Em um contexto pedagógico, como se distingue a escala de tons inteiros da escala pentatônica?", opts: ["São intercambiáveis — mesmo efeito sonoro", "A escala de tons inteiros tem 6 notas, flutuação total, acordes aumentados; a pentatônica tem 5 notas, serenidade, sem acorde de dominante", "A escala de tons inteiros é maior, a pentatônica é menor", "A escala de tons inteiros vem da Ásia, a pentatônica da França"], a: 1, fb: "Distinção essencial: escala de tons inteiros = 6 notas, somente tons inteiros, flutuação tonal, acordes aumentados. Pentatônica = 5 notas, sem semitons mas nem sempre tons inteiros (T–T–T½–T–T½), serenidade, cor oriental/folk." },

  // ── Tópico 3: A escala octatônica — 12 perguntas ─────────────────────────
  { q: "Quantas notas contém a escala octatônica?", opts: ["6 notas", "7 notas", "8 notas", "9 notas"], a: 2, fb: "A escala octatônica ('octa' = 8) contém 8 notas por oitava. Exemplo: Dó–Ré–Mib–Fá–Fá#–Sol#–Lá–Si–Dó. Ela alterna tom e semitom (ou semitom e tom, dependendo da versão)." },
  { q: "Qual é o princípio de construção da escala octatônica?", opts: ["Somente tons inteiros", "Alternância tom–semitom (ou semitom–tom)", "Somente semitons", "Terça menor + semitom em alternância"], a: 1, fb: "A escala octatônica alterna rigorosamente tom e semitom (T–½T–T–½T–T–½T–T–½T) ou o inverso (½T–T–½T–T–½T–T–½T–T). Essa simetria cria exatamente 8 notas dentro da oitava." },
  { q: "Qual acorde característico se encontra naturalmente na escala octatônica?", opts: ["O acorde aumentado", "O acorde de dominante sétima", "O acorde diminuto de sétima (dim7)", "O acorde de sexta napolitana"], a: 2, fb: "A escala octatônica contém 3 acordes diminutos de sétima (dim7): Dó–Mib–Fá#–Lá, Ré–Fá–Sol#–Si, e Mib–Fá#–Lá–Dó. É a escala ideal para construir sequências de dim7." },
  { q: "Quantas transposições distintas tem a escala octatônica?", opts: ["2 transposições", "3 transposições", "4 transposições", "12 transposições"], a: 1, fb: "A escala octatônica tem apenas 3 transposições distintas. Após 3 transposições de um semitom, retorna-se à mesma coleção de notas. É o Modo 2 de Messiaen, com exatamente 3 transposições." },
  { q: "Qual compositor russo usou maciçamente a escala octatônica em seus balés?", opts: ["Sergei Rachmaninov", "Piotr Ilitch Tchaikovsky", "Igor Stravinsky", "Dmitri Shostakovich"], a: 2, fb: "Igor Stravinsky é o mestre da escala octatônica, que emprega em seus grandes balés (O Pássaro de Fogo, Petrushka, A Sagração da Primavera). Ela lhe confere essa característica cor 'eslava mística'." },
  { q: "Qual compositor francês teorizou a escala octatônica como 'Modo 2 de transposições limitadas'?", opts: ["Claude Debussy", "Maurice Ravel", "Olivier Messiaen", "Gabriel Fauré"], a: 2, fb: "Olivier Messiaen sistematizou as escalas simétricas em 'Técnica da minha linguagem musical' (1944). Chamou a escala octatônica de 'Modo 2 de transposições limitadas' — 3 transposições possíveis contra 2 para o Modo 1." },
  { q: "A escala octatônica Dó–Ré–Mib–Fá–Fá#–Sol#–Lá–Si contém quantos acordes diminutos de sétima distintos?", opts: ["1 acorde dim7", "2 acordes dim7", "3 acordes dim7", "4 acordes dim7"], a: 2, fb: "Toda escala octatônica contém exatamente 3 acordes dim7 entrelaçados. Em Dó–Ré–Mib–Fá–Fá#–Sol#–Lá–Si: (1) Dó–Mib–Fá#–Lá, (2) Ré–Fá–Sol#–Si, e (3) Mib–Fá#–Lá–Dó. Esses três acordes cobrem todos os 12 sons cromáticos." },
  { q: "Qual é a cor sonora característica da escala octatônica?", opts: ["Flutuação onírica sem tensão", "Tensão simétrica, mistério, instabilidade organizada", "Serenidade, cor oriental", "Clareza tonal diatônica"], a: 1, fb: "A escala octatônica cria uma tensão simétrica particular — os acordes dim7 criam instabilidade mas de forma ordenada. A cor é escura, misteriosa, tensa — característica do estilo eslavo místico de Stravinsky e do esplendor de Messiaen." },
  { q: "A escala octatônica difere da escala de tons inteiros em que:", opts: ["A escala octatônica tem 6 notas, a de tons inteiros tem 8", "A escala octatônica alterna tom e semitom (8 notas), a de tons inteiros tem apenas tons inteiros (6 notas)", "São idênticas — dois nomes para a mesma escala", "A escala octatônica vem da Rússia, a de tons inteiros da França"], a: 1, fb: "Diferença fundamental: escala de tons inteiros = 6 notas, somente tons inteiros, acordes aumentados. Escala octatônica = 8 notas, alternância tom/semitom, acordes dim7. Duas cores muito distintas apesar da simetria comum." },
  { q: "Em 'Petrushka' de Stravinsky, o acorde 'bitonal' (Dó maior + Fá# maior simultaneamente) é possível graças a:", opts: ["A escala pentatônica", "A escala de tons inteiros", "A escala octatônica", "O sistema dodecafônico"], a: 2, fb: "O acorde 'Petrushka' (Dó–Mi–Sol + Fá#–Lá#–Dó#) é tornado coerente pela escala octatônica que contém ambos os conjuntos de notas simultaneamente. A simetria octatônica permite essa característica bitonalidade." },
  { q: "Por que o acorde diminuto de sétima (dim7) é particularmente ambíguo tonalmente?", opts: ["Porque contém um tritono", "Porque é composto de terças menores iguais — pode resolver para 4 tonalidades diferentes", "Porque é demasiado dissonante para resolver", "Porque não pertence a nenhuma escala"], a: 1, fb: "O acorde dim7 é composto de 4 terças menores sobrepostas (Dó–Mib–Fá#–Lá). Como todas as suas terças são iguais, é perfeitamente simétrico e pode resolver para 4 tonalidades maiores ou menores diferentes — daí sua extrema ambiguidade tonal." },
  { q: "A escala octatônica é chamada de 'Modo 2' por Messiaen porque:", opts: ["É a segunda escala que ele inventou", "É a escala com 2 transposições distintas", "É o segundo modo em sua classificação dos modos de transposições limitadas (depois da escala de tons inteiros)", "É a escala que começa no 2° grau"], a: 2, fb: "Messiaen numerou seus modos segundo sua complexidade e número de transposições. Modo 1 (2 transposições) = escala de tons inteiros. Modo 2 (3 transposições) = escala octatônica. A numeração segue uma ordem lógica em seu sistema." },

  // ── Tópico 4: A escala pentatônica — 12 perguntas ────────────────────────
  { q: "Quantas notas contém a escala pentatônica?", opts: ["4 notas", "5 notas", "6 notas", "7 notas"], a: 1, fb: "A escala pentatônica ('penta' = 5) contém 5 notas. A versão mais comum em Dó é: Dó–Ré–Mi–Sol–Lá. Ela é obtida suprimindo o Fá e o Si da escala de Dó maior." },
  { q: "O que caracteriza a escala pentatônica em relação à escala maior?", opts: ["Contém mais semitons", "Não contém nenhum semitom — o que elimina qualquer tensão direcional", "Contém um tritono central", "É sempre menor"], a: 1, fb: "A escala pentatônica maior Dó–Ré–Mi–Sol–Lá não contém nenhum semitom. A ausência de semitom significa ausência de nota sensível e de tritono — portanto nenhuma tensão direcional em direção a uma resolução. O som é sereno, aberto." },
  { q: "Qual nota está ausente da pentatônica Dó–Ré–Mi–Sol–Lá em relação a Dó maior?", opts: ["Ré e Sol", "Fá e Si", "Mi e Lá", "Sol e Dó"], a: 1, fb: "A escala de Dó maior é Dó–Ré–Mi–Fá–Sol–Lá–Si–Dó. Suprimindo o Fá e o Si (as duas notas que formam o tritono e criam a tensão sensível-tônica), obtém-se a pentatônica Dó–Ré–Mi–Sol–Lá." },
  { q: "Por que a escala pentatônica é universal — presente em quase todas as culturas musicais?", opts: ["Porque os gregos antigos a impuseram ao mundo", "Porque é fácil de tocar em qualquer instrumento", "Porque a ausência de semitom a torna naturalmente consonante e universalmente acessível", "Porque os 5 dedos da mão correspondem às 5 notas"], a: 2, fb: "A ausência de semitom na escala pentatônica a torna naturalmente agradável ao ouvido humano — nenhuma nota cria tensão em direção a uma resolução. É essa propriedade de consonância natural que explica sua presença nas músicas da África, Ásia, América e Europa." },
  { q: "A escala pentatônica é usada na música impressionista para evocar:", opts: ["A complexidade da harmonia romântica alemã", "A cor oriental, exótica ou antiga (gamelan, música chinesa)", "O contraponto barroco rigoroso", "A dança folk irlandesa"], a: 1, fb: "Debussy descobriu o gamelan javanês na Exposição Universal de 1889. Fascinado pela cor pentatônica dessa música, integrou-a em sua linguagem impressionista para evocar o Oriente, o sonho e o exotismo." },
  { q: "Qual é a relação entre a pentatônica e o jazz?", opts: ["O jazz evita sistematicamente a pentatônica", "A pentatônica (especialmente menor) é uma das bases do jazz e do blues", "O jazz usa apenas a pentatônica — nunca outras escalas", "A pentatônica é exclusiva da música clássica"], a: 1, fb: "A escala pentatônica menor (Dó–Mib–Fá–Sol–Sib) está no coração do blues e do jazz. Permite tocar 'de ouvido' sobre qualquer acorde sem dissonância — daí sua onipresença nos solos de improvisação de jazz e blues." },
  { q: "A pentatônica menor em Lá é:", opts: ["Lá–Si–Dó–Mi–Fá#", "Lá–Dó–Ré–Mi–Sol", "Lá–Sib–Dó–Réb–Mib", "Lá–Si–Ré–Mi–Sol#"], a: 1, fb: "A pentatônica menor em Lá é Lá–Dó–Ré–Mi–Sol. Estrutura: T½–T–T–T½–T. Corresponde à pentatônica maior de Dó (Dó–Ré–Mi–Sol–Lá) mas lida a partir de Lá — as duas compartilham exatamente as mesmas notas." },
  { q: "Em 'Voiles' de Debussy, a seção central usa a pentatônica para criar:", opts: ["Um contraste de cor com a escala de tons inteiros da seção principal", "Uma tensão máxima antes da resolução final", "Um retorno à tonalidade de Dó maior", "Um efeito de fuga barroca"], a: 0, fb: "'Voiles' é construída sobre a escala de tons inteiros (Dó–Ré–Mi–Fá#–Sol#–Lá#) nas seções A. A seção central (B) usa a pentatônica (Sol#–Lá#–Dó–Ré–Mi) — esse contraste de cor é um golpe de gênio: duas escalas sem semitons, duas cores radicalmente diferentes." },
  { q: "A pentatônica é frequentemente usada na música folk e nos cantos tradicionais porque:", opts: ["É mais fácil de memorizar com apenas 5 notas", "A ausência de semitom permite uma entoação mais simples e adaptabilidade a vozes diferentes", "Os músicos tradicionais ignoravam as escalas de 7 notas", "Corresponde exatamente aos modos gregorianos"], a: 1, fb: "A ausência de semitom na pentatônica a torna especialmente adequada ao canto tradicional: sem tensão de entoação nos semitons, adaptável a diferentes registros, naturalmente consonante entre várias vozes." },
  { q: "Quantas transposições distintas tem a escala pentatônica?", opts: ["5 transposições distintas", "7 transposições distintas", "12 transposições distintas", "2 transposições distintas"], a: 2, fb: "A escala pentatônica tem 12 transposições distintas — não é um 'modo de transposições limitadas'. Ao contrário da escala de tons inteiros (2) ou da octatônica (3), a pentatônica pode ser transposta 12 vezes sem retornar a si mesma antes da oitava." },
  { q: "Qual é o acorde de dominante na escala pentatônica Dó–Ré–Mi–Sol–Lá?", opts: ["Sol–Si–Ré (V maior)", "Sol–Sib–Ré (V menor)", "Não há acorde de dominante no sentido funcional — Si e Fá estão ausentes", "Sol–Lá–Ré (acorde de quinta adicionada)"], a: 2, fb: "A escala pentatônica não contém Si (sensível) nem Fá. Porém o acorde de dominante V7 (Sol–Si–Ré–Fá) requer exatamente essas duas notas. Sem sensível, nenhuma tensão funcional em direção a I — é exatamente isso que confere à pentatônica seu caráter sem resolução." },
  { q: "Qual diferença fundamental existe entre a pentatônica e a escala de tons inteiros quanto à cor?", opts: ["A pentatônica soa mais 'moderna' do que a escala de tons inteiros", "A escala de tons inteiros cria a flutuação/mistério aumentado, a pentatônica cria a serenidade/clareza sem tensão", "A pentatônica é mais dissonante do que a escala de tons inteiros", "Não há diferença de cor — ambas são 'impressionistas'"], a: 1, fb: "Escala de tons inteiros: flutuação misteriosa e dissolução tonal (acordes aumentados, nenhuma nota sensível). Pentatônica: serenidade e clareza sem tensão (consonâncias naturais, cor folk ou oriental). Duas cores distintas apesar da ausência comum de semitons." },

  // ── Tópico 5: Modos de Messiaen e intercâmbio modal — 12 perguntas ────────
  { q: "O que é um 'modo de transposições limitadas' segundo Messiaen?", opts: ["Um modo que não pode ser transposto", "Um modo cujas transposições sucessivas reproduzem coleções de notas idênticas antes de percorrer todos os 12 semitons", "Um modo usado apenas na liturgia", "Um modo limitado a 5 notas"], a: 1, fb: "Um modo de transposições limitadas é uma escala cuja simetria interna faz com que certas transposições reproduzam exatamente a mesma coleção de notas. Ex.: a escala de tons inteiros em Dó e em Ré são duas escalas distintas, mas em Mi retorna a Dó — portanto apenas 2 transposições reais." },
  { q: "Quantos modos de transposições limitadas Messiaen catalogou em seu tratado de 1944?", opts: ["3 modos", "5 modos", "7 modos", "12 modos"], a: 2, fb: "Messiaen catalogou 7 modos de transposições limitadas em 'Técnica da minha linguagem musical' (1944). Cada modo é caracterizado por sua estrutura intervalar, seu número de transposições e sua 'cor' particular." },
  { q: "O Modo 1 de Messiaen tem 2 transposições e o Modo 2 tem 3. O que esse número crescente significa?", opts: ["Que o Modo 2 é mais complexo e mais dissonante", "Que quanto mais transposições, mais fraca é a simetria interna", "Quanto mais transposições distintas um modo tem, mais se aproxima de uma escala comum — a simetria se enfraquece", "Que o Modo 2 abrange mais tonalidades que o Modo 1"], a: 2, fb: "A lógica é o inverso do que se pensa: menos transposições = maior simetria interna (Modo 1: 2 transposições, simetria máxima). Mais transposições = simetria mais fraca. Uma escala comum tem 12 transposições distintas — nenhuma simetria interna particular." },
  { q: "Que efeito busca Messiaen ao usar os modos de transposições limitadas em suas obras?", opts: ["Maximizar a tensão harmônica para uma resolução dramática", "Criar uma cor única e inimitável através da simetria interna do modo", "Recuperar o contraponto barroco de Bach", "Tornar a música acessível ao grande público"], a: 1, fb: "Messiaen buscava explicitamente a 'cor' harmônica — cada modo de transposições limitadas possui uma cor única e reconhecível. Sua fé católica o levou a associar cores visuais precisas a cada modo (sinestesia)." },
  { q: "O que é o 'intercâmbio modal' (empréstimo modal)?", opts: ["Mudar de modo dentro de uma peça — passar de um modo para outro", "Tomar emprestado um acorde de um modo paralelo ou da escala eólia (menor natural) permanecendo na mesma tonalidade", "Transpor toda a peça para outro modo", "Usar acordes de duas tonalidades diferentes simultaneamente (bitonalidade)"], a: 1, fb: "O intercâmbio modal consiste em tomar emprestado pontualmente um acorde de outra escala baseada na mesma tônica. Em Dó maior, pode-se tomar emprestado IVm (Fá menor) do Dó menor, bVI (Láb) ou bVII (Sib) do Dó eólio — sem deixar Dó como centro tonal." },
  { q: "O acorde IVm emprestado em Dó maior é:", opts: ["Fá–Lá–Dó (Fá maior)", "Fá–Láb–Dó (Fá menor)", "Fá–Lá–Dó# (Fá aumentado)", "Fá–Láb–Dób (Fá diminuto)"], a: 1, fb: "IVm em Dó maior = acorde menor no 4° grau = Fá–Láb–Dó. Este acorde é tomado emprestado do Dó menor (ou eólio) onde o Lá é bemolado (Láb). É um dos empréstimos modais mais expressivos e frequentes na música pop e no jazz." },
  { q: "O acorde bVII em Dó maior (Sib–Ré–Fá) é emprestado do modo:", opts: ["Dó dórico", "Dó frígio", "Dó mixolídio", "Dó lídio"], a: 2, fb: "O modo mixolídio em Dó (Dó–Ré–Mi–Fá–Sol–Lá–Sib) é idêntico a Dó maior mas com um Sib em vez de Si. O acorde bVII (Sib maior = Sib–Ré–Fá) é natural no modo mixolídio. Seu efeito é característico do rock e da música modal." },
  { q: "Qual é o efeito típico do acorde bVI (Láb em Dó maior) em uma progressão em Dó?", opts: ["Clarifica a tonalidade de Dó", "Cria uma cor romântica e expressiva — um empréstimo muito surpreendente", "É equivalente a uma dominante secundária", "Sempre anuncia uma modulação"], a: 1, fb: "O acorde bVI (Láb–Dó–Mib) emprestado do Dó menor/eólio cria uma cor romântica repentina e muito expressiva. Sua cor 'inesperada' em um contexto maior é muito surpreendente — frequente em Schubert e na música pop (ex. o 'flat-six chord' das baladas rock)." },
  { q: "A progressão I–bVI–bVII–I em Dó maior usa empréstimos dos modos:", opts: ["Dórico e frígio somente", "Eólio (para bVI e bVII) e mixolídio (para bVII)", "Lídio e lócrio", "Nenhum empréstimo modal — são acordes diatônicos de Dó maior"], a: 1, fb: "Em Dó maior: bVI = Láb (emprestado do Dó eólio que tem Láb), bVII = Sib (emprestado do Dó mixolídio que tem Sib). Esta progressão (Dó–Láb–Sib–Dó) é muito frequente no rock e no pop — combina dois sabores modais distintos." },
  { q: "Por que o intercâmbio modal não cria uma modulação?", opts: ["Porque usa apenas acordes maiores", "Porque a tônica permanece a mesma — o empréstimo é pontual, não estrutural", "Porque não usa nenhum acorde de dominante", "Porque dura sempre menos de um compasso"], a: 1, fb: "O intercâmbio modal é um empréstimo pontual — a tônica não muda. Em Dó maior, tomar emprestado Láb (bVI) cria uma cor, mas Dó continua sendo o centro tonal. Uma modulação implica uma mudança de centro tonal confirmada por uma cadência na nova tonalidade." },
  { q: "O Modo 3 de Messiaen tem 4 transposições e 9 notas. Sua estrutura é:", opts: ["T–T–T–T–T–T–T–T (8 tons inteiros)", "T–½T–½T repetido 3 vezes (grupos de 3 notas)", "½T–T–½T–T repetido 4 vezes", "T–½T–T–T–½T–T–T–½T–T"], a: 1, fb: "O Modo 3 de Messiaen é construído sobre grupos de 3 notas: T–½T–½T, repetido 3 vezes para cobrir a oitava. Sua estrutura é Dó–Ré–Mib–Mi–Fá#–Sol–Sol#–Lá#–Si. Tem 4 transposições distintas e uma cor mais cromática e densa que os Modos 1 e 2." },
  { q: "Qual propriedade é comum a todos os modos de transposições limitadas de Messiaen?", opts: ["Contêm todos exatamente 6 notas", "Todos têm uma simetria interna que faz com que certas transposições produzam a mesma coleção de notas", "Todos derivam da escala maior por supressão de notas", "Todos são construídos sobre tritonos"], a: 1, fb: "A propriedade fundamental comum a todos os modos de transposições limitadas é sua simetria interna. Essa simetria faz com que, após um certo número de transposições (menos de 12), se retorne exatamente à mesma coleção de alturas. É o critério que os distingue das escalas 'comuns'." },
];

